(function(root){
  root.PM_QUESTIONS = [{"id": "Q01", "num": 1, "type": "single_choice", "point": 1, "stem": "Which of the following statements are considered FALSE?", "options": [{"key": "A", "text": "Operations are undertaken to sustain an organization's business."}, {"key": "B", "text": "Projects are undertaken to create unique products, services, or results."}, {"key": "C", "text": "Projects have well-defined objectives"}, {"key": "D", "text": "Operations are considered temporary work compared to project work"}], "note": "", "answerKey": "D", "answerText": "Operations are considered temporary work compared to project work", "chapter": "第1章 Introduction to Project Management", "chapterId": "CH01", "chapterNo": 1, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 1.pdf，第8页", "sourceExcerpt": "“A project is ‘a temporary endeavor undertaken to create a unique product, service, or result’”；“Operations is work done to sustain the business”。", "explanationMd": "**答案：** D. Operations are considered temporary work compared to project work  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 1.pdf`，第8页。  \n**原文摘录：** “A project is ‘a temporary endeavor undertaken to create a unique product, service, or result’”；“Operations is work done to sustain the business”。  \n**一致性或同义替换说明：** 课件明确说 project 是 temporary，operations 是 sustain the business；D 把 temporary 错放到 operations 上，因此为 false。", "knowledgePointIds": ["kp_project_vs_operations"], "knowledgePoint": "项目 vs 运营", "mnemonic": "项目=临时+独特；运营=持续+维持业务。", "trap": "看到 temporary 要想到 project，不要把 temporary 套到 operations。"}, {"id": "Q02", "num": 2, "type": "single_choice", "point": 1, "stem": "The role of a __________ is to provide direction and funding for a project.", "options": [{"key": "A", "text": "project manager"}, {"key": "B", "text": "project sponsor"}, {"key": "C", "text": "support staff member"}, {"key": "D", "text": "project team"}], "note": "", "answerKey": "B", "answerText": "project sponsor", "chapter": "第1章 Introduction to Project Management", "chapterId": "CH01", "chapterNo": 1, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 1.pdf，第12页", "sourceExcerpt": "“The project sponsor usually provides the direction and funding for the project”。", "explanationMd": "**答案：** B. project sponsor  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 1.pdf`，第12页。  \n**原文摘录：** “The project sponsor usually provides the direction and funding for the project”。  \n**一致性或同义替换说明：** 题干 “provide direction and funding for a project” 与课件原文一致，主体为 project sponsor。", "knowledgePointIds": ["kp_project_sponsor"], "knowledgePoint": "项目发起人", "mnemonic": "Sponsor = direction + funding。", "trap": "不要选 project manager；经理负责管理，sponsor 给方向和钱。"}, {"id": "Q03", "num": 3, "type": "single_choice", "point": 1, "stem": "Which of the following project objectives are FALSE?", "options": [{"key": "A", "text": "They have a definite beginning and end."}, {"key": "B", "text": "They have a unique purpose."}, {"key": "C", "text": "They are developed using progressive elaboration."}, {"key": "D", "text": "They are permanent in nature."}], "note": "", "answerKey": "D", "answerText": "They are permanent in nature.", "chapter": "第1章 Introduction to Project Management", "chapterId": "CH01", "chapterNo": 1, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 1.pdf，第8、12页", "sourceExcerpt": "第8页：“A project is ‘a temporary endeavor...’”；第12页：“A project ... is temporary”。", "explanationMd": "**答案：** D. They are permanent in nature.  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 1.pdf`，第8、12页。  \n**原文摘录：** 第8页：“A project is ‘a temporary endeavor...’”；第12页：“A project ... is temporary”。  \n**一致性或同义替换说明：** 课件原文确认项目是 temporary，因此 D 的 permanent in nature 与课件相反，是错误陈述。", "knowledgePointIds": ["kp_project_attributes_temporary"], "knowledgePoint": "项目属性：临时性", "mnemonic": "项目不是常设部门，是有终点的任务。", "trap": "FALSE 题中 permanent in nature 是反向陷阱。"}, {"id": "Q04", "num": 4, "type": "single_choice", "point": 1, "stem": "Which objective is true of projects?", "options": [{"key": "A", "text": "They have an indefinite beginning and end."}, {"key": "B", "text": "They have a unique purpose."}, {"key": "C", "text": "They are developed using regressive elaboration."}, {"key": "D", "text": "They are permanent in nature."}], "note": "", "answerKey": "B", "answerText": "They have a unique purpose.", "chapter": "第1章 Introduction to Project Management", "chapterId": "CH01", "chapterNo": 1, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 1.pdf，第12页", "sourceExcerpt": "“A project ... has a unique purpose”。", "explanationMd": "**答案：** B. They have a unique purpose.  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 1.pdf`，第12页。  \n**原文摘录：** “A project ... has a unique purpose”。  \n**一致性或同义替换说明：** B 选项与课件原文一致。", "knowledgePointIds": ["kp_project_attributes_unique"], "knowledgePoint": "项目属性：独特目的", "mnemonic": "Unique purpose 是项目关键词。", "trap": "regressive elaboration 和 permanent 都是干扰。"}, {"id": "Q05", "num": 5, "type": "single_choice", "point": 1, "stem": "Which of the following examples can be considered as 'internal stakeholders' for a project organization.", "options": [{"key": "A", "text": "Suppliers"}, {"key": "B", "text": "Public citizens"}, {"key": "C", "text": "Employees"}, {"key": "D", "text": "Competitors"}], "note": "", "answerKey": "C", "answerText": "Employees", "chapter": "第13章 Project Stakeholder Management", "chapterId": "CH13", "chapterNo": 13, "category": "2", "sharedGroup": "无", "source": "PPT/Chapter 13.pdf，第9页", "sourceExcerpt": "“Internal project stakeholders generally include the project sponsor, project team, support staff, and internal customers”；“External project stakeholders include ... competitors, suppliers ... concerned citizens”。", "explanationMd": "**答案：** C. Employees  \n**分类：** 2  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 13.pdf`，第9页。  \n**原文摘录：** “Internal project stakeholders generally include the project sponsor, project team, support staff, and internal customers”；“External project stakeholders include ... competitors, suppliers ... concerned citizens”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| Employees | project sponsor, project team, support staff, internal customers, top management... | 同义概括 | employees 是内部组织成员的概括；其他选项 suppliers/citizens/competitors 均在外部干系人范围。 |", "knowledgePointIds": ["kp_internal_stakeholders"], "knowledgePoint": "内部干系人", "mnemonic": "Employees 在组织内；suppliers/citizens/competitors 在组织外。", "trap": "stakeholder 不等于 customer；内部/外部按组织边界判断。"}, {"id": "Q06", "num": 6, "type": "single_choice", "point": 1, "stem": "Which is an example of a pre-initiation task?", "options": [{"key": "A", "text": "Drawing up a work breakdown structure"}, {"key": "B", "text": "Drafting the project charter"}, {"key": "C", "text": "Identifying stakeholders"}, {"key": "D", "text": "Developing a business case for a project"}], "note": "", "answerKey": "D", "answerText": "Developing a business case for a project", "chapter": "第3章 The Project Management Process Groups", "chapterId": "CH03", "chapterNo": 3, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 3.pdf，第15页", "sourceExcerpt": "“Senior managers often perform several pre-initiation tasks, including ... Develop a business case for a project”。", "explanationMd": "**答案：** D. Developing a business case for a project  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 3.pdf`，第15页。  \n**原文摘录：** “Senior managers often perform several pre-initiation tasks, including ... Develop a business case for a project”。  \n**一致性或同义替换说明：** D 选项与课件原文一致。", "knowledgePointIds": ["kp_business_case"], "knowledgePoint": "预启动任务：商业论证", "mnemonic": "Pre-initiation 先问“值不值得做”。", "trap": "WBS、charter、stakeholder identification 都更靠近启动/规划。"}, {"id": "Q07", "num": 7, "type": "single_choice", "point": 1, "stem": "Which of the following is true of the project life cycle?", "options": [{"key": "A", "text": "In the later phases of the project life cycle, the level of uncertainty is usually the highest."}, {"key": "B", "text": "It is much more expensive to make major changes to a project during the earlier phases than the latter phases."}, {"key": "C", "text": "More resources are usually needed during the initial phases of a project than during the middle or final phases."}, {"key": "D", "text": "In the early phases of a project life cycle, resource needs are usually lowest."}], "note": "", "answerKey": "D", "answerText": "In the early phases of a project life cycle, resource needs are usually lowest.", "chapter": "第2章 The Project Management and Information Technology Context", "chapterId": "CH02", "chapterNo": 2, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 2.pdf，第22页", "sourceExcerpt": "“In early phases of a project life cycle: resource needs are usually lowest”。", "explanationMd": "**答案：** D. In the early phases of a project life cycle, resource needs are usually lowest.  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 2.pdf`，第22页。  \n**原文摘录：** “In early phases of a project life cycle: resource needs are usually lowest”。  \n**一致性或同义替换说明：** D 选项与课件原文一致。", "knowledgePointIds": ["kp_lifecycle_resource_needs"], "knowledgePoint": "生命周期早期资源需求最低", "mnemonic": "早期：资源少、不确定高、改起来便宜。", "trap": "题目常把 early/later、expensive/cheap 对调。"}, {"id": "Q08", "num": 8, "type": "single_choice", "point": 1, "stem": "A project __________ is a specific point within a project's life cycle used to measure the progress toward the ultimate goal.", "options": [{"key": "A", "text": "risk register"}, {"key": "B", "text": "work break down structure"}, {"key": "C", "text": "milestone"}, {"key": "D", "text": "schedule network diagram"}], "note": "", "answerKey": "C", "answerText": "milestone", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "2 + 4", "sharedGroup": "共享选项组 G", "source": "PPT/Chapter 06.pdf，第12页", "sourceExcerpt": "“A milestone is a significant event that normally has no duration”；“They’re useful tools for setting schedule goals and monitoring progress”。", "explanationMd": "**答案：** C. milestone  \n**分类：** 2 + 4  \n**共享选项组：** 共享选项组 G  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 06.pdf`，第12页。  \n**原文摘录：** “A milestone is a significant event that normally has no duration”；“They’re useful tools for setting schedule goals and monitoring progress”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| specific point within a project's life cycle | significant event | 同义概括 | milestone 是项目中的关键事件/节点。 |\n| used to measure progress | monitoring progress | 同义替换 | 二者都指用里程碑跟踪进展。 |\n\n**排除法说明：** 同组选项中 risk register、WBS、schedule network diagram 均不是“生命周期中的进度节点”。", "knowledgePointIds": ["kp_milestone"], "knowledgePoint": "里程碑", "mnemonic": "Milestone = 点，不是任务段。", "trap": "milestone 不是 WBS，也不是网络图；它是关键节点。"}, {"id": "Q09", "num": 9, "type": "single_choice", "point": 1, "stem": "Which processes include acquiring and developing the project team, performing quality assurance, distributing information, managing stakeholder expectations, and conducting procurements?", "options": [{"key": "A", "text": "monitoring and controlling"}, {"key": "B", "text": "planning"}, {"key": "C", "text": "executing"}, {"key": "D", "text": "initiation"}], "note": "", "answerKey": "C", "answerText": "executing", "chapter": "第3章 The Project Management Process Groups", "chapterId": "CH03", "chapterNo": 3, "category": "2", "sharedGroup": "无", "source": "PPT/Chapter 3.pdf，第9-10页", "sourceExcerpt": "课件 Table 3-1 的 Executing 列包含 “Perform quality assurance”“Acquire project team”“Develop project team”“Conduct procurements”“Manage stakeholder engagement”等。", "explanationMd": "**答案：** C. executing  \n**分类：** 2  \n**共享选项组：** 无  \n**依据来源：** 课件；教材可辅助核对。  \n**具体出处：** `PPT/Chapter 3.pdf`，第9-10页，Table 3-1；教材 PDF 第111页有与题干更接近的执行过程示例。  \n**原文摘录：** 课件 Table 3-1 的 Executing 列包含 “Perform quality assurance”“Acquire project team”“Develop project team”“Conduct procurements”“Manage stakeholder engagement”等。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| acquiring and developing the project team | Acquire project team；Develop project team | 词形调整 | 题干把两个执行过程合并表述。 |\n| distributing information / managing stakeholder expectations | Manage communications / Manage stakeholder engagement | PMBOK 术语版本差异 | 题干用旧版/通俗表述，课件用 PMBOK 第五版表述，均在 Executing 列。 |\n| conducting procurements | Conduct procurements | 高度一致 | 指向执行过程组。 |", "knowledgePointIds": ["kp_executing_process_group"], "knowledgePoint": "执行过程组", "mnemonic": "Acquire/Develop team + QA + distribute info + stakeholder + procurement = executing。", "trap": "看到“做事情、组织资源实施”通常是 executing。"}, {"id": "Q10", "num": 10, "type": "single_choice", "point": 1, "stem": "Which knowledge area is responsible for helping organize schedule data and report on resource utilization?", "options": [{"key": "A", "text": "Time/Schedule"}, {"key": "B", "text": "Cost"}, {"key": "C", "text": "Scope"}, {"key": "D", "text": "Scope"}], "note": "**⚠️ 注意：原题C和D选项文字相同，均为\"Scope\"，疑似出题/截图问题。**", "answerKey": "A", "answerText": "Time/Schedule", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "2", "sharedGroup": "无", "source": "PPT/Chapter 06.pdf，第7页", "sourceExcerpt": "“Estimating activity resources: estimating how many resources a project team should use”；“Developing the schedule: analyzing activity sequences, activity resource estimates, and activity duration estimates to create the project schedule”。", "explanationMd": "**答案：** A. Time/Schedule  \n**分类：** 2  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 06.pdf`，第7页。  \n**原文摘录：** “Estimating activity resources: estimating how many resources a project team should use”；“Developing the schedule: analyzing activity sequences, activity resource estimates, and activity duration estimates to create the project schedule”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| organize schedule data | create the project schedule | 同义概括 | 进度管理负责形成和维护进度信息。 |\n| report on resource utilization | activity resource estimates | 相关概念改写 | 资源使用与活动资源估算/进度数据相关，最匹配 Time/Schedule。 |\n\n**题目格式说明：** 原题 C、D 均为 “Scope”，选项疑似重复；不影响 A 为最合理答案。", "knowledgePointIds": ["kp_schedule_management_processes"], "knowledgePoint": "进度/时间管理", "mnemonic": "时间管理七步：plan, define, sequence, resources, durations, develop, control。", "trap": "题中 Scope 选项重复，是原题问题；按 schedule data 选 Time/Schedule。"}, {"id": "Q11", "num": 11, "type": "single_choice", "point": 1, "stem": "__________ management is the process for ensuring that all project activities necessary to design, plan and implement a project are effective and efficient with respect to the purpose of the objective and its performance?", "options": [{"key": "A", "text": "Time/Schedule"}, {"key": "B", "text": "Scope"}, {"key": "C", "text": "Quality"}, {"key": "D", "text": "Risk"}], "note": "", "answerKey": "C", "answerText": "Quality", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "2", "sharedGroup": "无", "source": "PPT/Chapter 08.pdf，第7页", "sourceExcerpt": "“Project quality management ensures that the project will satisfy the needs for which it was undertaken”。", "explanationMd": "**答案：** C. Quality  \n**分类：** 2  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 08.pdf`，第7页。  \n**原文摘录：** “Project quality management ensures that the project will satisfy the needs for which it was undertaken”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| ensuring project activities ... are effective and efficient | ensures that the project will satisfy the needs | 同义概括 | 题干强调活动有效高效，课件强调满足项目需求，均指质量管理目标。 |\n| purpose of the objective and its performance | needs for which it was undertaken | 同义替换 | 都指项目被开展的目的/需求。 |", "knowledgePointIds": ["kp_quality_management_purpose"], "knowledgePoint": "质量管理目标", "mnemonic": "Quality = satisfy needs / fitness for use。", "trap": "不要把质量题误选成 Scope 或 Risk。"}, {"id": "Q12", "num": 12, "type": "single_choice", "point": 1, "stem": "Using the formula for calculating the number of communication channels, how many channels would six people require?", "options": [{"key": "A", "text": "12"}, {"key": "B", "text": "16"}, {"key": "C", "text": "15"}, {"key": "D", "text": "14"}], "note": "", "answerKey": "C", "answerText": "15", "chapter": "第10章 Project Communications Management", "chapterId": "CH10", "chapterNo": 10, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 10.pdf，第17页", "sourceExcerpt": "“Number of communications channels = n(n-1) / 2”。", "explanationMd": "**答案：** C. 15  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 10.pdf`，第17页。  \n**原文摘录：** “Number of communications channels = n(n-1) / 2”。  \n**一致性或同义替换说明：** 六人沟通渠道数为 `6 * (6 - 1) / 2 = 15`。", "knowledgePointIds": ["kp_communication_channels"], "knowledgePoint": "沟通渠道公式", "mnemonic": "人数乘前一个数再除以2。", "trap": "别把人数直接乘2，也别忘记除2。"}, {"id": "Q13", "num": 13, "type": "single_choice", "point": 1, "stem": "Which document describes the predicted revenue for projects that an organization is pursuing?", "options": [{"key": "A", "text": "progress reports"}, {"key": "B", "text": "status reports"}, {"key": "C", "text": "forecasts"}, {"key": "D", "text": "lessons-learned reports"}], "note": "", "answerKey": "C", "answerText": "forecasts", "chapter": "第10章 Project Communications Management", "chapterId": "CH10", "chapterNo": 10, "category": "2", "sharedGroup": "无", "source": "PPT/Chapter 10.pdf，第28页", "sourceExcerpt": "“Forecasts predict future project status and progress based on past information and trends”。", "explanationMd": "**答案：** C. forecasts  \n**分类：** 2  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 10.pdf`，第28页。  \n**原文摘录：** “Forecasts predict future project status and progress based on past information and trends”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| predicted revenue for projects | predict future project status and progress | 同义/场景改写 | forecasts 的核心是预测未来信息；选项中只有 forecasts 表示预测类文件。 |", "knowledgePointIds": ["kp_forecasts"], "knowledgePoint": "预测报告", "mnemonic": "forecast = future / predicted。", "trap": "status 是当前状态，progress 是进展，lessons learned 是经验教训。"}, {"id": "Q14", "num": 14, "type": "single_choice", "point": 1, "stem": "A(n) __________ is a tool used to demonstrate the relationship between demands and other artefacts.", "options": [{"key": "A", "text": "requirements traceability matrix"}, {"key": "B", "text": "Gantt chart"}, {"key": "C", "text": "power/interest grid"}, {"key": "D", "text": "issue log"}], "note": "", "answerKey": "A", "answerText": "requirements traceability matrix", "chapter": "第5章 Project Scope Management", "chapterId": "CH05", "chapterNo": 5, "category": "2 + 4", "sharedGroup": "共享选项组 A", "source": "PPT/Chapter 05.pdf，第16页", "sourceExcerpt": "“A requirements traceability matrix (RTM) is a table that lists requirements, various attributes of each requirement, and the status of the requirements to ensure that all requirements are addressed”。", "explanationMd": "**答案：** A. requirements traceability matrix  \n**分类：** 2 + 4  \n**共享选项组：** 共享选项组 A  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 05.pdf`，第16页。  \n**原文摘录：** “A requirements traceability matrix (RTM) is a table that lists requirements, various attributes of each requirement, and the status of the requirements to ensure that all requirements are addressed”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| demands | requirements | 同义替换 | demands 在题干中对应项目需求 requirements。 |\n| relationship between demands and other artefacts | lists requirements, attributes, and status | 同义概括 | RTM 用表格追踪需求与属性/状态等信息的关系。 |\n\n**排除法说明：** 同组选项中 Gantt chart 属于进度展示，power/interest grid 属于干系人分类，issue log 属于问题记录，只有 RTM 对应需求跟踪。", "knowledgePointIds": ["kp_rtm"], "knowledgePoint": "需求跟踪矩阵 RTM", "mnemonic": "Requirements/demands + relationship/trace = RTM。", "trap": "别被同组选项 Gantt、power/interest、issue log 迷惑。"}, {"id": "Q15", "num": 15, "type": "single_choice", "point": 1, "stem": "Which of the following are sub-processes associated with project schedule/time management?", "options": [{"key": "A", "text": "Sequence activities"}, {"key": "B", "text": "Continuous Improvement"}, {"key": "C", "text": "Distribution of information"}, {"key": "D", "text": "Validate work involved"}], "note": "", "answerKey": "A", "answerText": "Sequence activities", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "1 + 4", "sharedGroup": "共享选项组 C", "source": "PPT/Chapter 06.pdf，第7页", "sourceExcerpt": "“Sequencing activities: identifying and documenting the relationships between project activities”。", "explanationMd": "**答案：** A. Sequence activities  \n**分类：** 1 + 4  \n**共享选项组：** 共享选项组 C  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 06.pdf`，第7页。  \n**原文摘录：** “Sequencing activities: identifying and documenting the relationships between project activities”。  \n**一致性或同义替换说明：** A 选项与课件中的进度管理过程名称一致。  \n**排除法说明：** 同组选项中 B 属质量，C 属沟通，D 属范围；题干问 schedule/time management，故选 A。", "knowledgePointIds": ["kp_sequence_activities"], "knowledgePoint": "排列活动顺序", "mnemonic": "relationships among activities = sequence。", "trap": "Validate scope 属范围，Distribution 信息属沟通，Continuous improvement 属质量。"}, {"id": "Q16", "num": 16, "type": "single_choice", "point": 1, "stem": "Outsourcing to provide extra workers during periods of peak workloads can be much more economical than trying to fill entire projects with internal resources. Which advantages does this characteristic of outsourcing provide organizations?", "options": [{"key": "A", "text": "offers control over all aspects of projects that suppliers carry out"}, {"key": "B", "text": "provides flexibility"}, {"key": "C", "text": "shifts accountability from external suppliers to internal staff"}, {"key": "D", "text": "helps avoid any form of dependency on suppliers"}], "note": "", "answerKey": "B", "answerText": "provides flexibility", "chapter": "第12章 Project Procurement Management", "chapterId": "CH12", "chapterNo": 12, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 12.pdf，第9页", "sourceExcerpt": "课件列出 outsourcing 的好处：“To provide flexibility”。", "explanationMd": "**答案：** B. provides flexibility  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 12.pdf`，第9页。  \n**原文摘录：** 课件列出 outsourcing 的好处：“To provide flexibility”。  \n**一致性或同义替换说明：** B 选项与课件原文一致；题干中的高峰期外包用工是 flexibility 的具体场景。", "knowledgePointIds": ["kp_outsourcing_flexibility"], "knowledgePoint": "外包优势：灵活性", "mnemonic": "Peak workload + extra workers = flexibility。", "trap": "外包不会让组织控制供应商所有方面，也不会消除依赖。"}, {"id": "Q17", "num": 17, "type": "single_choice", "point": 1, "stem": "Resource allocation is used for __________.", "options": [{"key": "A", "text": "boosting employee available work time, focus on project timelines and budgets"}, {"key": "B", "text": "helping assign the best team for the job, and optimize how work is assigned"}, {"key": "C", "text": "monitoring the project and track its progress"}, {"key": "D", "text": "resolving resource conflicts by delaying tasks"}], "note": "", "answerKey": "B", "answerText": "helping assign the best team for the job, and optimize how work is assigned", "chapter": "第9章 Project Human Resource Management", "chapterId": "CH09", "chapterNo": 9, "category": "3.2 + 4", "sharedGroup": "共享选项组 D", "source": "教材 PDF，第174页", "sourceExcerpt": "图中 “Resource Allocation” 阶段对应结果 “Assign resources”。", "explanationMd": "**答案：** B. helping assign the best team for the job, and optimize how work is assigned  \n**分类：** 3.2 + 4  \n**共享选项组：** 共享选项组 D  \n**依据来源：** 教材；排除法。课件中未找到 resource allocation 的直接定义。  \n**具体出处：** 教材 PDF，第174页，Figure 4-3 “Planning process for selecting IT projects”。  \n**原文摘录：** 图中 “Resource Allocation” 阶段对应结果 “Assign resources”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 教材原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| helping assign the best team for the job | Assign resources | 同义扩展 | 题干将“分配资源”具体化为分配合适团队。 |\n| optimize how work is assigned | Resource Allocation | 同义概括 | allocation 的核心就是资源/工作分派优化。 |\n\n**排除法说明：** Q38 的 D 已由课件直接定义为 resource leveling；Q23 的 C 对应 resource histogram；因此 resource allocation 对应 B。", "knowledgePointIds": ["kp_resource_allocation"], "knowledgePoint": "资源分配", "mnemonic": "Allocation = assign best team/work。", "trap": "monitor progress 是资源直方图；delaying tasks 是资源平衡。"}, {"id": "Q18", "num": 18, "type": "single_choice", "point": 1, "stem": "A(n) __________ is a tool used for categorizing stakeholders during a change to allow them to be effectively managed.", "options": [{"key": "A", "text": "requirements traceability matrix"}, {"key": "B", "text": "Gantt chart"}, {"key": "C", "text": "power/interest grid"}, {"key": "D", "text": "issue log"}], "note": "", "answerKey": "C", "answerText": "power/interest grid", "chapter": "第13章 Project Stakeholder Management", "chapterId": "CH13", "chapterNo": 13, "category": "2 + 4", "sharedGroup": "共享选项组 A", "source": "PPT/Chapter 13.pdf，第13页", "sourceExcerpt": "“A power/interest grid can be used to group stakeholders based on their level of authority (power) and their level of concern (interest) for project outcomes”。", "explanationMd": "**答案：** C. power/interest grid  \n**分类：** 2 + 4  \n**共享选项组：** 共享选项组 A  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 13.pdf`，第13页。  \n**原文摘录：** “A power/interest grid can be used to group stakeholders based on their level of authority (power) and their level of concern (interest) for project outcomes”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| categorizing stakeholders ... effectively managed | group stakeholders based on authority and concern | 同义替换 | categorizing 对应 group；有效管理对应按 power/interest 制定管理方式。 |\n\n**排除法说明：** 同组选项中 RTM 属需求跟踪，Gantt chart 属进度计划，issue log 属问题记录；干系人分类工具为 power/interest grid。", "knowledgePointIds": ["kp_power_interest_grid"], "knowledgePoint": "权力/利益方格", "mnemonic": "Stakeholders + categorize + power/interest = power-interest grid。", "trap": "RTM 管需求，Gantt 管进度，issue log 记问题。"}, {"id": "Q19", "num": 19, "type": "single_choice", "point": 1, "stem": "Which process term is used for identifying and documenting relationships among the project activities?", "options": [{"key": "A", "text": "milestone"}, {"key": "B", "text": "activity attribute"}, {"key": "C", "text": "activity sequence"}, {"key": "D", "text": "schedule baseline"}], "note": "", "answerKey": "C", "answerText": "activity sequence", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "2 + 4", "sharedGroup": "共享选项组 H", "source": "PPT/Chapter 06.pdf，第7、14页", "sourceExcerpt": "第7页：“Sequencing activities: identifying and documenting the relationships between project activities”；第14页：“A dependency or relationship is the sequencing of project activities or tasks”。", "explanationMd": "**答案：** C. activity sequence  \n**分类：** 2 + 4  \n**共享选项组：** 共享选项组 H  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 06.pdf`，第7、14页。  \n**原文摘录：** 第7页：“Sequencing activities: identifying and documenting the relationships between project activities”；第14页：“A dependency or relationship is the sequencing of project activities or tasks”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| process term | Sequencing activities | 词形替换 | 题目将过程名名词化为 activity sequence。 |\n| relationships among the project activities | relationships between project activities | 高度一致 | 核心名词和动词基本一致。 |\n\n**排除法说明：** milestone 是事件，activity attribute 是属性，schedule baseline 是批准后的进度基准，只有 activity sequence 对应活动关系排序。", "knowledgePointIds": ["kp_activity_sequence"], "knowledgePoint": "活动排序/活动顺序", "mnemonic": "relationships among activities = activity sequence。", "trap": "milestone 是重大事件，不是记录活动关系的过程。"}, {"id": "Q20", "num": 20, "type": "single_choice", "point": 1, "stem": "Which term is used to determine the degree to which a system performs its intended function?", "options": [{"key": "A", "text": "reliability"}, {"key": "B", "text": "validity"}, {"key": "C", "text": "maintainability"}, {"key": "D", "text": "functionality"}], "note": "", "answerKey": "D", "answerText": "functionality", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "1 + 4", "sharedGroup": "共享选项组 E", "source": "PPT/Chapter 08.pdf，第10页", "sourceExcerpt": "“Functionality is the degree to which a system performs its intended function”。", "explanationMd": "**答案：** D. functionality  \n**分类：** 1 + 4  \n**共享选项组：** 共享选项组 E  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 08.pdf`，第10页。  \n**原文摘录：** “Functionality is the degree to which a system performs its intended function”。  \n**一致性或同义替换说明：** 题干与课件原文一致。  \n**排除法说明：** reliability 指正常条件下按预期运行；maintainability 指维护难易；validity 不是课件此处定义的属性。", "knowledgePointIds": ["kp_functionality"], "knowledgePoint": "功能性", "mnemonic": "Functionality 看“能不能实现功能”。", "trap": "reliability 看正常条件下是否稳定按预期运行。"}, {"id": "Q21", "num": 21, "type": "single_choice", "point": 1, "stem": "What term is used to determine the ability of a product or service to perform as expected under normal conditions?", "options": [{"key": "A", "text": "reliability"}, {"key": "B", "text": "performance"}, {"key": "C", "text": "maintainability"}, {"key": "D", "text": "functionality"}], "note": "", "answerKey": "A", "answerText": "reliability", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "1 + 4", "sharedGroup": "共享选项组 E", "source": "PPT/Chapter 08.pdf，第10页", "sourceExcerpt": "“Reliability is the ability of a product or service to perform as expected under normal conditions”。", "explanationMd": "**答案：** A. reliability  \n**分类：** 1 + 4  \n**共享选项组：** 共享选项组 E  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 08.pdf`，第10页。  \n**原文摘录：** “Reliability is the ability of a product or service to perform as expected under normal conditions”。  \n**一致性或同义替换说明：** 题干与课件原文一致。  \n**排除法说明：** functionality 是履行预期功能的程度，maintainability 是维护便利性；题干的 normal conditions 指向 reliability。", "knowledgePointIds": ["kp_reliability"], "knowledgePoint": "可靠性", "mnemonic": "Reliable = normal condition + expected performance。", "trap": "不要与 functionality 混淆；functionality 强调功能是否具备。"}, {"id": "Q22", "num": 22, "type": "single_choice", "point": 1, "stem": "Which action involves reducing the impact of a risk event by reducing the probability of its occurrence?", "options": [{"key": "A", "text": "risk avoidance"}, {"key": "B", "text": "risk acceptance"}, {"key": "C", "text": "risk transference"}, {"key": "D", "text": "risk mitigation"}], "note": "", "answerKey": "D", "answerText": "risk mitigation", "chapter": "第11章 Project Risk Management", "chapterId": "CH11", "chapterNo": 11, "category": "3.1 + 4", "sharedGroup": "共享选项组 I", "source": "教材 PDF，第483页", "sourceExcerpt": "“Risk mitigation or reducing the impact of a risk event by reducing the probability of its occurrence”。", "explanationMd": "**答案：** D. risk mitigation  \n**分类：** 3.1 + 4  \n**共享选项组：** 共享选项组 I  \n**依据来源：** 教材；排除法。课件第53页仅列出四种 negative risk response strategies，未给出 mitigation 定义。  \n**具体出处：** 教材 PDF，第483页。  \n**原文摘录：** “Risk mitigation or reducing the impact of a risk event by reducing the probability of its occurrence”。  \n**一致性或同义替换说明：** 题干 “reducing the impact ... by reducing the probability” 与教材原文高度一致。  \n**排除法说明：** 同组选项中 transference 是转移给第三方；acceptance 是接受后果；avoidance 是消除威胁；降低概率/影响为 mitigation。", "knowledgePointIds": ["kp_risk_mitigation"], "knowledgePoint": "风险减轻", "mnemonic": "Mitigate = reduce probability/impact。", "trap": "transference 是转移给第三方，acceptance 是接受，avoidance 是规避。"}, {"id": "Q23", "num": 23, "type": "single_choice", "point": 1, "stem": "A Resource histogram is used to __________.", "options": [{"key": "A", "text": "boost employee available work time, focus on project timelines and budgets"}, {"key": "B", "text": "help assign the best team for the job, and optimize how work is assigned"}, {"key": "C", "text": "monitor the project and track its progress"}, {"key": "D", "text": "resolve resource conflicts by delaying tasks"}], "note": "", "answerKey": "C", "answerText": "monitoring the project and track its progress", "chapter": "第9章 Project Human Resource Management", "chapterId": "CH09", "chapterNo": 9, "category": "2 + 4", "sharedGroup": "共享选项组 D", "source": "PPT/Chapter 9.pdf，第35页", "sourceExcerpt": "“A resource histogram is a column chart that shows the number of resources assigned to a project over time”。", "explanationMd": "**答案：** C. monitoring the project and track its progress  \n**分类：** 2 + 4  \n**共享选项组：** 共享选项组 D  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 9.pdf`，第35页。  \n**原文摘录：** “A resource histogram is a column chart that shows the number of resources assigned to a project over time”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| monitor the project and track its progress | shows resources assigned ... over time | 功能概括 | 资源直方图通过时间维度显示资源分配，可用于跟踪资源使用状态。 |\n\n**排除法说明：** 同组选项中 D 已是 resource leveling；B 对应 resource allocation；A 与 resource histogram 定义不符。", "knowledgePointIds": ["kp_resource_histogram"], "knowledgePoint": "资源直方图", "mnemonic": "Histogram = bar over time。", "trap": "不是分配最佳团队，也不是通过延迟任务解决冲突。"}, {"id": "Q24", "num": 24, "type": "single_choice", "point": 1, "stem": "In project time/schedule management, which process involves determining the total elapsed time for the work to be done, plus any associated waiting time?", "options": [{"key": "A", "text": "estimating activity durations"}, {"key": "B", "text": "developing the schedule"}, {"key": "C", "text": "controlling the schedule"}, {"key": "D", "text": "estimating activity resources"}], "note": "", "answerKey": "A", "answerText": "estimating activity durations", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 06.pdf，第7、24页", "sourceExcerpt": "第7页：“Estimating activity durations: estimating the number of work periods that are needed to complete individual activities”；第24页：“Duration includes the actual amount of time worked on an activity plus elapsed time”。", "explanationMd": "**答案：** A. estimating activity durations  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 06.pdf`，第7、24页。  \n**原文摘录：** 第7页：“Estimating activity durations: estimating the number of work periods that are needed to complete individual activities”；第24页：“Duration includes the actual amount of time worked on an activity plus elapsed time”。  \n**一致性或同义替换说明：** 题干中的 “total elapsed time ... plus waiting time” 对应 duration；过程名称与 A 选项一致。", "knowledgePointIds": ["kp_estimate_durations"], "knowledgePoint": "估算活动持续时间", "mnemonic": "Duration = elapsed time + waiting time。", "trap": "develop schedule 是综合分析后形成进度计划。"}, {"id": "Q25", "num": 25, "type": "single_choice", "point": 1, "stem": "__________ is a Logical Relationship in which a Successor Activity cannot start until a Predecessor Activity has started.", "options": [{"key": "A", "text": "start-to-start"}, {"key": "B", "text": "finish-to-start"}, {"key": "C", "text": "finish-to-finish"}, {"key": "D", "text": "start-to-finish"}], "note": "", "answerKey": "A", "answerText": "start-to-start", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 06.pdf，第21页", "sourceExcerpt": "“Start-to-start (SS) ... Task (B) cannot start until task (A) starts”。", "explanationMd": "**答案：** A. start-to-start  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件图表。  \n**具体出处：** `PPT/Chapter 06.pdf`，第21页，Figure 6-3 “Task Dependency Types”。  \n**原文摘录：** “Start-to-start (SS) ... Task (B) cannot start until task (A) starts”。  \n**一致性或同义替换说明：** 题干 “Successor Activity cannot start until a Predecessor Activity has started” 与图表描述一致。", "knowledgePointIds": ["kp_start_to_start"], "knowledgePoint": "开始-开始关系 SS", "mnemonic": "SS：start waits for start。", "trap": "finish-to-start 是后续开始等前置完成。"}, {"id": "Q26", "num": 26, "type": "single_choice", "point": 1, "stem": "A(n) __________ is a tool used for assisting in the planning and scheduling of projects of all sizes.", "options": [{"key": "A", "text": "requirements traceability matrix"}, {"key": "B", "text": "Gantt chart"}, {"key": "C", "text": "power/interest grid"}, {"key": "D", "text": "issue log"}], "note": "", "answerKey": "B", "answerText": "Gantt chart", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "2 + 4", "sharedGroup": "共享选项组 A", "source": "PPT/Chapter 06.pdf，第27页", "sourceExcerpt": "“Gantt charts provide a standard format for displaying project schedule information by listing project activities and their corresponding start and finish dates”。", "explanationMd": "**答案：** B. Gantt chart  \n**分类：** 2 + 4  \n**共享选项组：** 共享选项组 A  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 06.pdf`，第27页。  \n**原文摘录：** “Gantt charts provide a standard format for displaying project schedule information by listing project activities and their corresponding start and finish dates”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| assisting in the planning and scheduling of projects | displaying project schedule information | 同义概括 | Gantt chart 用于展示进度活动、开始和完成日期，是计划和排程常用工具。 |\n\n**排除法说明：** RTM、power/interest grid、issue log 分别属于需求、干系人、问题管理，不是项目计划排程图。", "knowledgePointIds": ["kp_gantt_chart"], "knowledgePoint": "甘特图", "mnemonic": "Gantt = 条形进度图。", "trap": "与网络图不同，Gantt 强调时间条和排程展示。"}, {"id": "Q27", "num": 27, "type": "single_choice", "point": 1, "stem": "The critical path is the longest path through a network diagram, and it represents the shortest amount of __________.", "options": [{"key": "A", "text": "time"}, {"key": "B", "text": "resources"}, {"key": "C", "text": "slack"}, {"key": "D", "text": "activity"}], "note": "", "answerKey": "A", "answerText": "time", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 06.pdf，第34页", "sourceExcerpt": "“A critical path ... determines the earliest time by which the project can be completed”；“The critical path is the longest path through the network diagram”。", "explanationMd": "**答案：** A. time  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 06.pdf`，第34页。  \n**原文摘录：** “A critical path ... determines the earliest time by which the project can be completed”；“The critical path is the longest path through the network diagram”。  \n**一致性或同义替换说明：** 题干前半句与课件一致，后半句 “shortest amount of time” 对应 “earliest time ... completed”。", "knowledgePointIds": ["kp_critical_path_time"], "knowledgePoint": "关键路径代表最短完成时间", "mnemonic": "路径最长，工期最短可完成时间。", "trap": "关键路径只考虑 time，不是 resources/slack/activity。"}, {"id": "Q28", "num": 28, "type": "single_choice", "point": 1, "stem": "A project __________ visualizes the sequential and logical relationship between tasks in a project setting.", "options": [{"key": "A", "text": "risk register"}, {"key": "B", "text": "work break down structure"}, {"key": "C", "text": "milestone"}, {"key": "D", "text": "schedule network diagram"}], "note": "", "answerKey": "D", "answerText": "schedule network diagram", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "2 + 4", "sharedGroup": "共享选项组 G", "source": "PPT/Chapter 06.pdf，第16页", "sourceExcerpt": "“A network diagram is a schematic display of the logical relationships among, or sequencing of, project activities”。", "explanationMd": "**答案：** D. schedule network diagram  \n**分类：** 2 + 4  \n**共享选项组：** 共享选项组 G  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 06.pdf`，第16页。  \n**原文摘录：** “A network diagram is a schematic display of the logical relationships among, or sequencing of, project activities”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| visualizes the sequential and logical relationship between tasks | schematic display of the logical relationships ... sequencing of project activities | 同义替换 | visualizes 对应 schematic display；tasks 对应 project activities。 |\n\n**排除法说明：** milestone 是节点，WBS 是范围分解，risk register 是风险文件；只有 schedule network diagram 展示活动逻辑关系。", "knowledgePointIds": ["kp_schedule_network_diagram"], "knowledgePoint": "进度网络图", "mnemonic": "Network diagram = logical/sequential relationships。", "trap": "milestone 是点，WBS 是范围分解，risk register 是风险文件。"}, {"id": "Q29", "num": 29, "type": "single_choice", "point": 1, "stem": "Which of the following is true of program managers?", "options": [{"key": "A", "text": "They report to project managers who represent the next level in the hierarchy."}, {"key": "B", "text": "They recognize that managing a program is simpler than managing a project."}, {"key": "C", "text": "They provide leadership and direction for project managers heading the projects within a program."}, {"key": "D", "text": "They are responsible solely for the delivery of project results."}], "note": "", "answerKey": "C", "answerText": "They provide leadership and direction for project managers heading the projects within a program.", "chapter": "第1章 Introduction to Project Management", "chapterId": "CH01", "chapterNo": 1, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 1.pdf，第26页", "sourceExcerpt": "“A program manager provides leadership and direction for the project managers heading the projects within the program”。", "explanationMd": "**答案：** C. They provide leadership and direction for project managers heading the projects within a program.  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 1.pdf`，第26页。  \n**原文摘录：** “A program manager provides leadership and direction for the project managers heading the projects within the program”。  \n**一致性或同义替换说明：** C 选项与课件原文高度一致。", "knowledgePointIds": ["kp_program_manager"], "knowledgePoint": "项目集经理角色", "mnemonic": "Program manager manages project managers。", "trap": "项目集管理通常比单项目更复杂，不是向项目经理汇报。"}, {"id": "Q30", "num": 30, "type": "single_choice", "point": 1, "stem": "Which of the following is the true objective of the project risk management knowledge area?", "options": [{"key": "A", "text": "to ensure the project includes only the work required, for completing the project successfully"}, {"key": "B", "text": "to ensure smooth flow of information from either between two people or a group"}, {"key": "C", "text": "increase the probability and/or impact of the opportunities and decrease the probability and/or impact of the threats"}, {"key": "D", "text": "Describe the end-to-end supplier process that the project will use to acquire its goods and services"}], "note": "", "answerKey": "C", "answerText": "increase the probability and/or impact of the opportunities and decrease the probability and/or impact of the threats", "chapter": "第11章 Project Risk Management", "chapterId": "CH11", "chapterNo": 11, "category": "2 + 4", "sharedGroup": "共享选项组 B", "source": "PPT/Chapter 11.pdf，第10页", "sourceExcerpt": "“The goal of project risk management is to minimize potential negative risks while maximizing potential positive risks”。", "explanationMd": "**答案：** C. increase the probability and/or impact of the opportunities and decrease the probability and/or impact of the threats  \n**分类：** 2 + 4  \n**共享选项组：** 共享选项组 B  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 11.pdf`，第10页。  \n**原文摘录：** “The goal of project risk management is to minimize potential negative risks while maximizing potential positive risks”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| increase opportunities / decrease threats | maximizing positive risks / minimize negative risks | 同义替换 | opportunities 即 positive risks；threats 即 negative risks。 |\n\n**排除法说明：** 共享选项组 B 中，C 是风险管理目标；A、B、D 分别对应范围、沟通、采购。", "knowledgePointIds": ["kp_risk_management_objective"], "knowledgePoint": "风险管理目标", "mnemonic": "机会↑，威胁↓。", "trap": "风险管理同时处理正面风险和负面风险。"}, {"id": "Q31", "num": 31, "type": "single_choice", "point": 1, "stem": "How are 'revenues minus expenditures' best defined?", "options": [{"key": "A", "text": "capital"}, {"key": "B", "text": "profits"}, {"key": "C", "text": "costs"}, {"key": "D", "text": "accounting"}], "note": "", "answerKey": "B", "answerText": "profits", "chapter": "第7章 Project Cost Management", "chapterId": "CH07", "chapterNo": 7, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 07.pdf，第9页", "sourceExcerpt": "“Profits are revenues minus expenditures”。", "explanationMd": "**答案：** B. profits  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 07.pdf`，第9页。  \n**原文摘录：** “Profits are revenues minus expenditures”。  \n**一致性或同义替换说明：** 题干中的 revenues minus expenditures 与课件原文一致。", "knowledgePointIds": ["kp_profits"], "knowledgePoint": "利润", "mnemonic": "profit = revenue - expenditure。", "trap": "不要把 revenue 本身当 profit。"}, {"id": "Q32", "num": 32, "type": "single_choice", "point": 1, "stem": "Which of the following is the true objective of the project scope management knowledge area?", "options": [{"key": "A", "text": "to ensure the project includes only the work required, for completing the project successfully"}, {"key": "B", "text": "to ensure smooth flow of information from either between two people or a group"}, {"key": "C", "text": "increase the probability and/or impact of the opportunities and decrease the probability and/or impact of the threats"}, {"key": "D", "text": "Describe the end-to-end supplier process that the project will use to acquire its goods and services"}], "note": "", "answerKey": "A", "answerText": "to ensure the project includes only the work required, for completing the project successfully", "chapter": "第5章 Project Scope Management", "chapterId": "CH05", "chapterNo": 5, "category": "1 + 4", "sharedGroup": "共享选项组 B", "source": "PPT/Chapter 05.pdf，第42页", "sourceExcerpt": "“Project scope management includes the processes required to ensure that the project addresses all the work required, and only the work required, to complete the project successfully”。", "explanationMd": "**答案：** A. to ensure the project includes only the work required, for completing the project successfully  \n**分类：** 1 + 4  \n**共享选项组：** 共享选项组 B  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 05.pdf`，第42页。  \n**原文摘录：** “Project scope management includes the processes required to ensure that the project addresses all the work required, and only the work required, to complete the project successfully”。  \n**一致性或同义替换说明：** A 选项与课件原文高度一致。  \n**排除法说明：** 共享选项组 B 中，A 是范围管理，B 是沟通管理，C 是风险管理，D 是采购管理。题干问 scope management，故选 A。", "knowledgePointIds": ["kp_scope_management_objective"], "knowledgePoint": "范围管理目标", "mnemonic": "all the work required, and only the work required。", "trap": "只做所需工作是 scope 关键词。"}, {"id": "Q33", "num": 33, "type": "single_choice", "point": 1, "stem": "__________ is an estimate of the value of the physical work actually completed.", "options": [{"key": "A", "text": "Planned cost"}, {"key": "B", "text": "Cost estimate"}, {"key": "C", "text": "Planned value"}, {"key": "D", "text": "Earned value"}], "note": "", "answerKey": "D", "answerText": "Earned value", "chapter": "第7章 Project Cost Management", "chapterId": "CH07", "chapterNo": 7, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 07.pdf，第31页", "sourceExcerpt": "“The earned value (EV) ... is an estimate of the value of the physical work actually completed”。", "explanationMd": "**答案：** D. Earned value  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 07.pdf`，第31页。  \n**原文摘录：** “The earned value (EV) ... is an estimate of the value of the physical work actually completed”。  \n**一致性或同义替换说明：** 题干与课件原文一致。", "knowledgePointIds": ["kp_earned_value"], "knowledgePoint": "挣值 EV", "mnemonic": "EV = value of work actually completed。", "trap": "不是预算总额，也不是实际成本。"}, {"id": "Q34", "num": 34, "type": "single_choice", "point": 1, "stem": "Which process involves building individual and group skills to enhance project performance?", "options": [{"key": "A", "text": "developing the human resource plan"}, {"key": "B", "text": "developing the project team"}, {"key": "C", "text": "acquiring the project team"}, {"key": "D", "text": "managing the project team"}], "note": "", "answerKey": "B", "answerText": "developing the project team", "chapter": "第9章 Project Human Resource Management", "chapterId": "CH09", "chapterNo": 9, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 9.pdf，第9页", "sourceExcerpt": "“Developing the project team: building individual and group skills to enhance project performance”。", "explanationMd": "**答案：** B. developing the project team  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 9.pdf`，第9页。  \n**原文摘录：** “Developing the project team: building individual and group skills to enhance project performance”。  \n**一致性或同义替换说明：** 题干与课件原文一致。", "knowledgePointIds": ["kp_develop_project_team"], "knowledgePoint": "建设项目团队", "mnemonic": "Develop team = build skills。", "trap": "acquire team 是获得人员，manage team 是跟踪和解决问题。"}, {"id": "Q35", "num": 35, "type": "single_choice", "point": 1, "stem": "Outsourcing suppliers can often provide economies of scale, especially for hardware and software, that may not be available to the client alone. Which benefit does this offer an organization?", "options": [{"key": "A", "text": "reduction in costs"}, {"key": "B", "text": "increased flexibility"}, {"key": "C", "text": "increased accountability"}, {"key": "D", "text": "access to specific skills"}], "note": "", "answerKey": "A", "answerText": "reduction in costs", "chapter": "第12章 Project Procurement Management", "chapterId": "CH12", "chapterNo": 12, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 12.pdf，第9页", "sourceExcerpt": "课件列出 outsourcing 的好处：“To reduce both fixed and recurrent costs”。", "explanationMd": "**答案：** A. reduction in costs  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 12.pdf`，第9页。  \n**原文摘录：** 课件列出 outsourcing 的好处：“To reduce both fixed and recurrent costs”。  \n**一致性或同义替换说明：** A 的 reduction in costs 与课件 “reduce ... costs” 一致。", "knowledgePointIds": ["kp_outsourcing_cost_reduction"], "knowledgePoint": "外包优势：降低成本", "mnemonic": "Economies of scale = cost reduction。", "trap": "题干说 economies of scale 时通常指成本降低。"}, {"id": "Q36", "num": 36, "type": "single_choice", "point": 1, "stem": "What process involves identifying and controlling the functional and physical design characteristics of products and their support documentation, and ensures that the descriptions of the project's products are correct and complete?", "options": [{"key": "A", "text": "Configuration management"}, {"key": "B", "text": "NPV analysis"}, {"key": "C", "text": "Change Management"}, {"key": "D", "text": "Project time management"}], "note": "", "answerKey": "A", "answerText": "Configuration management", "chapter": "第4章 Project Integration Management", "chapterId": "CH04", "chapterNo": 4, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 04.pdf，第49页", "sourceExcerpt": "“Configuration management ensures that the descriptions of the project’s products are correct and complete”；“Involves identifying and controlling the functional and physical design characteristics of products and their support documentation”。", "explanationMd": "**答案：** A. Configuration management  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 04.pdf`，第49页。  \n**原文摘录：** “Configuration management ensures that the descriptions of the project’s products are correct and complete”；“Involves identifying and controlling the functional and physical design characteristics of products and their support documentation”。  \n**一致性或同义替换说明：** 题干与课件两句原文高度一致。", "knowledgePointIds": ["kp_configuration_management"], "knowledgePoint": "配置管理", "mnemonic": "Configuration = identify + control characteristics。", "trap": "不是普通 change control；它更关注产品配置项和文档一致性。"}, {"id": "Q37", "num": 37, "type": "single_choice", "point": 1, "stem": "__________ is \"the selection, prioritization and control of an organization's programmes and projects, in line with its strategic objectives and capacity to deliver\".", "options": [{"key": "A", "text": "Scope Management"}, {"key": "B", "text": "Procurement Management"}, {"key": "C", "text": "Project Management"}, {"key": "D", "text": "Portfolio Management"}], "note": "", "answerKey": "D", "answerText": "Portfolio Management", "chapter": "第1章 Introduction to Project Management", "chapterId": "CH01", "chapterNo": 1, "category": "2", "sharedGroup": "无", "source": "PPT/Chapter 1.pdf，第27页", "sourceExcerpt": "“As part of project portfolio management, organizations group and manage projects and programs as a portfolio of investments that contribute to the entire enterprise’s success”；“Portfolio managers ... select and analyze projects from a strategic perspective”。", "explanationMd": "**答案：** D. Portfolio Management  \n**分类：** 2  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 1.pdf`，第27页。  \n**原文摘录：** “As part of project portfolio management, organizations group and manage projects and programs as a portfolio of investments that contribute to the entire enterprise’s success”；“Portfolio managers ... select and analyze projects from a strategic perspective”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| selection, prioritization and control of programmes and projects | group and manage projects and programs；select and analyze projects | 同义概括 | 题干是 portfolio management 的标准化定义，课件用“组合管理、从战略角度选择和分析项目”表达同一概念。 |\n| in line with strategic objectives | from a strategic perspective | 同义替换 | 二者都强调项目组合与战略一致。 |", "knowledgePointIds": ["kp_portfolio_management"], "knowledgePoint": "项目组合管理", "mnemonic": "Portfolio = strategic selection/prioritization。", "trap": "portfolio 管战略投资组合，program 管相关项目群。"}, {"id": "Q38", "num": 38, "type": "single_choice", "point": 1, "stem": "Resource levelling is used for __________.", "options": [{"key": "A", "text": "boosting employee available work time, focusing on project timelines and budgets"}, {"key": "B", "text": "helping assign the best team for the job, and optimize how work is assigned"}, {"key": "C", "text": "monitoring the project and track its progress"}, {"key": "D", "text": "resolving resource conflicts by delaying tasks"}], "note": "", "answerKey": "D", "answerText": "resolving resource conflicts by delaying tasks", "chapter": "第9章 Project Human Resource Management", "chapterId": "CH09", "chapterNo": 9, "category": "1 + 4", "sharedGroup": "共享选项组 D", "source": "PPT/Chapter 9.pdf，第42页", "sourceExcerpt": "“Resource leveling is a technique for resolving resource conflicts by delaying tasks”。", "explanationMd": "**答案：** D. resolving resource conflicts by delaying tasks  \n**分类：** 1 + 4  \n**共享选项组：** 共享选项组 D  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 9.pdf`，第42页。  \n**原文摘录：** “Resource leveling is a technique for resolving resource conflicts by delaying tasks”。  \n**一致性或同义替换说明：** D 选项与课件原文一致。  \n**排除法说明：** resource leveling 的定义已直接出现；resource histogram 和 resource allocation 不能选择。", "knowledgePointIds": ["kp_resource_leveling"], "knowledgePoint": "资源平衡", "mnemonic": "Leveling = delay tasks to resolve conflicts。", "trap": "allocation 是分配，histogram 是展示/跟踪。"}, {"id": "Q39", "num": 39, "type": "single_choice", "point": 1, "stem": "In a __________ organizational structure, teams report to multiple leaders.", "options": [{"key": "A", "text": "project"}, {"key": "B", "text": "symbolic"}, {"key": "C", "text": "matrix"}, {"key": "D", "text": "functional"}], "note": "", "answerKey": "C", "answerText": "matrix", "chapter": "第2章 The Project Management and Information Technology Context", "chapterId": "CH02", "chapterNo": 2, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 2.pdf，第9页", "sourceExcerpt": "“Matrix: ... personnel often report to two or more bosses”。", "explanationMd": "**答案：** C. matrix  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 2.pdf`，第9页。  \n**原文摘录：** “Matrix: ... personnel often report to two or more bosses”。  \n**一致性或同义替换说明：** “report to multiple leaders” 与 “report to two or more bosses” 高度一致。", "knowledgePointIds": ["kp_matrix_org"], "knowledgePoint": "矩阵型组织结构", "mnemonic": "Matrix = multiple bosses。", "trap": "只要题中 multiple leaders/bosses，优先选 matrix。"}, {"id": "Q40", "num": 40, "type": "single_choice", "point": 1, "stem": "__________ tests are performed to know if a complete build aligns with functional and non-functional requirements made for it.", "options": [{"key": "A", "text": "Integration"}, {"key": "B", "text": "Unit"}, {"key": "C", "text": "User acceptance"}, {"key": "D", "text": "System"}], "note": "", "answerKey": "D", "answerText": "System", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "2 + 4", "sharedGroup": "共享选项组 F", "source": "PPT/Chapter 08.pdf，第48页", "sourceExcerpt": "“System testing tests the entire system as one entity”。", "explanationMd": "**答案：** D. System  \n**分类：** 2 + 4  \n**共享选项组：** 共享选项组 F  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 08.pdf`，第48页。  \n**原文摘录：** “System testing tests the entire system as one entity”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| complete build aligns with functional and non-functional requirements | entire system as one entity | 同义概括 | 完整构建/完整系统对应 system testing 的测试对象。 |\n\n**排除法说明：** integration 测组合组件，unit 测单个组件，user acceptance 由最终用户验收；完整构建整体测试对应 system。", "knowledgePointIds": ["kp_system_testing"], "knowledgePoint": "系统测试", "mnemonic": "System = entire system as one entity。", "trap": "integration testing 是多个单元组合后测试。"}, {"id": "Q41", "num": 41, "type": "single_choice", "point": 1, "stem": "Which term is used to measure of how well your product does what you intend?", "options": [{"key": "A", "text": "conformance to requirements"}, {"key": "B", "text": "fitness for use"}, {"key": "C", "text": "critical chain scheduling"}, {"key": "D", "text": "free slack"}], "note": "", "answerKey": "B", "answerText": "fitness for use", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "2", "sharedGroup": "无", "source": "PPT/Chapter 08.pdf，第6页", "sourceExcerpt": "“Fitness for use: A product can be used as it was intended”。", "explanationMd": "**答案：** B. fitness for use  \n**分类：** 2  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 08.pdf`，第6页。  \n**原文摘录：** “Fitness for use: A product can be used as it was intended”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| how well your product does what you intend | product can be used as it was intended | 同义替换 | 都强调产品是否按预期用途发挥作用。 |", "knowledgePointIds": ["kp_fitness_for_use"], "knowledgePoint": "适用性", "mnemonic": "Fitness for use = used as intended。", "trap": "它是质量的核心定义之一，不是单纯 performance。"}, {"id": "Q42", "num": 42, "type": "single_choice", "point": 1, "stem": "Which of the following is the true objective of the project communications management knowledge area?", "options": [{"key": "A", "text": "to ensure the project includes only the work required, for completing the project successfully"}, {"key": "B", "text": "to ensure smooth flow of information from either between two people or a group"}, {"key": "C", "text": "increase the probability and/or impact of the opportunities and decrease the probability and/or impact of the threats"}, {"key": "D", "text": "Describe the end-to-end supplier process that the project will use to acquire its goods and services"}], "note": "", "answerKey": "B", "answerText": "to ensure smooth flow of information from either between two people or a group", "chapter": "第10章 Project Communications Management", "chapterId": "CH10", "chapterNo": 10, "category": "2 + 4", "sharedGroup": "共享选项组 B", "source": "PPT/Chapter 10.pdf，第46页", "sourceExcerpt": "“The goal of project communications management is to ensure timely and appropriate generation, collection, dissemination, storage, and disposition of project information”。", "explanationMd": "**答案：** B. to ensure smooth flow of information from either between two people or a group  \n**分类：** 2 + 4  \n**共享选项组：** 共享选项组 B  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 10.pdf`，第46页。  \n**原文摘录：** “The goal of project communications management is to ensure timely and appropriate generation, collection, dissemination, storage, and disposition of project information”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| smooth flow of information | timely and appropriate generation, collection, dissemination... | 同义概括 | 题干用“信息顺畅流动”概括课件的信息生成、收集、传播等过程。 |\n\n**排除法说明：** 共享选项组 B 中，B 对应 communications；A、C、D 分别对应 scope、risk、procurement。", "knowledgePointIds": ["kp_communications_objective"], "knowledgePoint": "沟通管理目标", "mnemonic": "Communications = smooth flow of information。", "trap": "范围、风险、采购都有各自目标，题干有 information flow 选 communications。"}, {"id": "Q43", "num": 43, "type": "single_choice", "point": 1, "stem": "Which document contains a deliverable-oriented grouping of the work involved in a project that defines the total scope of the project?", "options": [{"key": "A", "text": "project charter"}, {"key": "B", "text": "business case"}, {"key": "C", "text": "project scope statement"}, {"key": "D", "text": "work breakdown structure"}], "note": "", "answerKey": "D", "answerText": "work breakdown structure", "chapter": "第5章 Project Scope Management", "chapterId": "CH05", "chapterNo": 5, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 05.pdf，第21页", "sourceExcerpt": "“A WBS is a deliverable-oriented grouping of the work involved in a project that defines the total scope of the project”。", "explanationMd": "**答案：** D. work breakdown structure  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 05.pdf`，第21页。  \n**原文摘录：** “A WBS is a deliverable-oriented grouping of the work involved in a project that defines the total scope of the project”。  \n**一致性或同义替换说明：** 题干与课件原文一致，WBS 即 work breakdown structure。", "knowledgePointIds": ["kp_wbs"], "knowledgePoint": "工作分解结构 WBS", "mnemonic": "WBS = deliverable-oriented grouping。", "trap": "WBS 是范围分解，不是进度网络图。"}, {"id": "Q44", "num": 44, "type": "single_choice", "point": 1, "stem": "Which process involves documenting how risk is assessed and who is responsible for doing it?", "options": [{"key": "A", "text": "identifying risks"}, {"key": "B", "text": "planning risk management"}, {"key": "C", "text": "performing qualitative risk analysis"}, {"key": "D", "text": "performing quantitative risk analysis"}], "note": "", "answerKey": "B", "answerText": "planning risk management", "chapter": "第11章 Project Risk Management", "chapterId": "CH11", "chapterNo": 11, "category": "2", "sharedGroup": "无", "source": "PPT/Chapter 11.pdf，第14、17、18页", "sourceExcerpt": "第14页：“Planning risk management: Deciding how to approach and plan the risk management activities”；第17页：“risk management plan ... documents the procedures for managing risk”；第18页列出 “Roles and responsibilities”“Risk probability and impact”。", "explanationMd": "**答案：** B. planning risk management  \n**分类：** 2  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 11.pdf`，第14、17、18页。  \n**原文摘录：** 第14页：“Planning risk management: Deciding how to approach and plan the risk management activities”；第17页：“risk management plan ... documents the procedures for managing risk”；第18页列出 “Roles and responsibilities”“Risk probability and impact”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| how risk is assessed | Risk probability and impact | 同义概括 | 风险评估涉及概率和影响。 |\n| who is responsible for doing it | Roles and responsibilities | 同义替换 | 责任归属是风险管理计划内容。 |", "knowledgePointIds": ["kp_planning_risk_management"], "knowledgePoint": "规划风险管理", "mnemonic": "Plan risk = document how and who。", "trap": "qualitative/quantitative 是后续分析风险。"}, {"id": "Q45", "num": 45, "type": "single_choice", "point": 1, "stem": "Which process involves numerically analysing the effect of identified risks on overall project objectives?", "options": [{"key": "A", "text": "performing qualitative risk analysis"}, {"key": "B", "text": "identifying risks"}, {"key": "C", "text": "planning risk responses"}, {"key": "D", "text": "performing quantitative risk analysis"}], "note": "", "answerKey": "D", "answerText": "performing quantitative risk analysis", "chapter": "第11章 Project Risk Management", "chapterId": "CH11", "chapterNo": 11, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 11.pdf，第15页", "sourceExcerpt": "“Performing quantitative risk analysis: Numerically estimating the effects of risks on project objectives”。", "explanationMd": "**答案：** D. performing quantitative risk analysis  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 11.pdf`，第15页。  \n**原文摘录：** “Performing quantitative risk analysis: Numerically estimating the effects of risks on project objectives”。  \n**一致性或同义替换说明：** 题干与课件原文高度一致。", "knowledgePointIds": ["kp_quantitative_risk_analysis"], "knowledgePoint": "实施定量风险分析", "mnemonic": "Quantitative = numerically analyzing。", "trap": "qualitative 是按概率/影响等进行优先级排序。"}, {"id": "Q46", "num": 46, "type": "single_choice", "point": 1, "stem": "Which of the following is the true objective of the project procurement management knowledge area?", "options": [{"key": "A", "text": "to ensure the project includes only the work required, for completing the project successfully"}, {"key": "B", "text": "to ensure smooth flow of information from either between two people or a group"}, {"key": "C", "text": "increase the probability and/or impact of the opportunities and decrease the probability and/or impact of the threats"}, {"key": "D", "text": "Describe the end-to-end supplier process that the project will use to acquire its goods and services"}], "note": "", "answerKey": "D", "answerText": "Describe the end-to-end supplier process that the project will use to acquire its goods and services", "chapter": "第12章 Project Procurement Management", "chapterId": "CH12", "chapterNo": 12, "category": "2 + 4", "sharedGroup": "共享选项组 B", "source": "PPT/Chapter 12.pdf，第12页", "sourceExcerpt": "“Project procurement management: Acquiring goods and services for a project from outside the performing organization”。", "explanationMd": "**答案：** D. Describe the end-to-end supplier process that the project will use to acquire its goods and services  \n**分类：** 2 + 4  \n**共享选项组：** 共享选项组 B  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 12.pdf`，第12页。  \n**原文摘录：** “Project procurement management: Acquiring goods and services for a project from outside the performing organization”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| end-to-end supplier process | acquiring goods and services from outside the performing organization | 同义概括 | supplier process 是采购外部商品和服务的过程化表述。 |\n\n**排除法说明：** 共享选项组 B 中，A、B、C 已分别对应 scope、communications、risk；题干问 procurement，故选 D。", "knowledgePointIds": ["kp_procurement_objective"], "knowledgePoint": "采购管理目标", "mnemonic": "Procurement = acquiring goods/services from outside。", "trap": "supplier / acquire goods and services 是采购关键词。"}, {"id": "Q47", "num": 47, "type": "single_choice", "point": 1, "stem": "Which process helps develop an accurate projection of a project's financial expenses and benefits?", "options": [{"key": "A", "text": "critical path analysis"}, {"key": "B", "text": "fast tracking"}, {"key": "C", "text": "life cycle costing"}, {"key": "D", "text": "crashing"}], "note": "", "answerKey": "C", "answerText": "life cycle costing", "chapter": "第7章 Project Cost Management", "chapterId": "CH07", "chapterNo": 7, "category": "2", "sharedGroup": "无", "source": "PPT/Chapter 07.pdf，第9页", "sourceExcerpt": "“Life cycle costing considers the total cost of ownership, or development plus support costs, for a project”；同页还列出 “Cash flow analysis determines the estimated annual costs and benefits”。", "explanationMd": "**答案：** C. life cycle costing  \n**分类：** 2  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 07.pdf`，第9页。  \n**原文摘录：** “Life cycle costing considers the total cost of ownership, or development plus support costs, for a project”；同页还列出 “Cash flow analysis determines the estimated annual costs and benefits”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| projection of a project's financial expenses and benefits | total cost of ownership；estimated annual costs and benefits | 同义概括 | 选项中只有 life cycle costing 属于财务成本/收益预测相关方法。 |", "knowledgePointIds": ["kp_life_cycle_costing"], "knowledgePoint": "生命周期成本法", "mnemonic": "Life cycle = development + support。", "trap": "不要只看初始采购或开发成本。"}, {"id": "Q48", "num": 48, "type": "single_choice", "point": 1, "stem": "__________ involves shifting of the consequence and impact of the risk to a third party.", "options": [{"key": "A", "text": "risk avoidance"}, {"key": "B", "text": "risk acceptance"}, {"key": "C", "text": "risk transference"}, {"key": "D", "text": "risk mitigation"}], "note": "", "answerKey": "C", "answerText": "risk transference", "chapter": "第11章 Project Risk Management", "chapterId": "CH11", "chapterNo": 11, "category": "3.1 + 4", "sharedGroup": "共享选项组 I", "source": "教材 PDF，第483页", "sourceExcerpt": "“Risk transference or shifting the consequence of a risk and responsibility for its management to a third party”。", "explanationMd": "**答案：** C. risk transference  \n**分类：** 3.1 + 4  \n**共享选项组：** 共享选项组 I  \n**依据来源：** 教材；排除法。课件第53页只列策略名称，未给出 transference 定义。  \n**具体出处：** 教材 PDF，第483页。  \n**原文摘录：** “Risk transference or shifting the consequence of a risk and responsibility for its management to a third party”。  \n**一致性或同义替换说明：** 题干 “shifting ... consequence and impact ... to a third party” 与教材原文高度一致。  \n**排除法说明：** 同组选项中 mitigation 是降低概率/影响；acceptance 是接受后果；avoidance 是消除风险原因；转移给第三方为 transference。", "knowledgePointIds": ["kp_risk_transference"], "knowledgePoint": "风险转移", "mnemonic": "Transfer = third party。", "trap": "mitigation 是降低概率/影响，不是转给别人。"}, {"id": "Q49", "num": 49, "type": "single_choice", "point": 1, "stem": "__________ is a risk response strategy whereby the project team acts to ensure that an opportunity occurs.", "options": [{"key": "A", "text": "risk enhancement"}, {"key": "B", "text": "risk acceptance"}, {"key": "C", "text": "risk sharing"}, {"key": "D", "text": "risk exploitation"}], "note": "", "answerKey": "D", "answerText": "risk exploitation", "chapter": "第11章 Project Risk Management", "chapterId": "CH11", "chapterNo": 11, "category": "3.2", "sharedGroup": "无", "source": "教材 PDF，第483页", "sourceExcerpt": "“Risk exploitation or doing whatever you can to make sure the positive risk happens”。", "explanationMd": "**答案：** D. risk exploitation  \n**分类：** 3.2  \n**共享选项组：** 无  \n**依据来源：** 教材。课件第55页只列出正面风险策略名称，未给出 exploitation 定义。  \n**具体出处：** 教材 PDF，第483页。  \n**原文摘录：** “Risk exploitation or doing whatever you can to make sure the positive risk happens”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 教材原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| ensure that an opportunity occurs | make sure the positive risk happens | 同义替换 | opportunity 即 positive risk；ensure occurs 即 make sure happens。 |", "knowledgePointIds": ["kp_risk_exploitation"], "knowledgePoint": "风险开拓/利用", "mnemonic": "Exploit = make opportunity happen。", "trap": "只用于机会/正面风险，不是威胁。"}, {"id": "Q50", "num": 50, "type": "single_choice", "point": 1, "stem": "Which of the following are sub-processes associated with project communication management?", "options": [{"key": "A", "text": "Sequence activities"}, {"key": "B", "text": "Continuous Improvement"}, {"key": "C", "text": "Distribution of information"}, {"key": "D", "text": "Validate work involved"}], "note": "", "answerKey": "C", "answerText": "Distribution of information", "chapter": "第10章 Project Communications Management", "chapterId": "CH10", "chapterNo": 10, "category": "2 + 4", "sharedGroup": "共享选项组 C", "source": "PPT/Chapter 10.pdf，第6页", "sourceExcerpt": "“Managing communications: Creating, distributing, storing, retrieving, and disposing of project communications”。", "explanationMd": "**答案：** C. Distribution of information  \n**分类：** 2 + 4  \n**共享选项组：** 共享选项组 C  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 10.pdf`，第6页。  \n**原文摘录：** “Managing communications: Creating, distributing, storing, retrieving, and disposing of project communications”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| Distribution of information | distributing ... project communications | 词形替换 | 选项把 managing communications 中的 distributing 抽成名词短语。 |\n\n**排除法说明：** A 属进度，B 属质量，D 属范围；题干问 communication management，故选 C。", "knowledgePointIds": ["kp_information_distribution"], "knowledgePoint": "信息分发", "mnemonic": "Distribution = communications。", "trap": "Sequence 属进度，Validate 属范围，Continuous improvement 属质量。"}, {"id": "Q51", "num": 51, "type": "single_choice", "point": 1, "stem": "Which of the following are sub-processes associated with project quality management?", "options": [{"key": "A", "text": "Sequence activities"}, {"key": "B", "text": "Continuous Improvement"}, {"key": "C", "text": "Distribution of information"}, {"key": "D", "text": "Validate work involved"}], "note": "", "answerKey": "B", "answerText": "Continuous Improvement", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "2 + 4", "sharedGroup": "共享选项组 C", "source": "PPT/Chapter 08.pdf，第12页", "sourceExcerpt": "“Another goal of quality assurance is continuous quality improvement”。", "explanationMd": "**答案：** B. Continuous Improvement  \n**分类：** 2 + 4  \n**共享选项组：** 共享选项组 C  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 08.pdf`，第12页。  \n**原文摘录：** “Another goal of quality assurance is continuous quality improvement”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| Continuous Improvement | continuous quality improvement | 省略修饰语 | 选项省略 quality，但仍对应质量保证/质量管理。 |\n\n**排除法说明：** A 属进度，C 属沟通，D 属范围；题干问 quality management，故选 B。", "knowledgePointIds": ["kp_continuous_improvement"], "knowledgePoint": "持续改进", "mnemonic": "Continuous improvement = quality。", "trap": "题干点名 quality management 时，不要选沟通或范围过程。"}, {"id": "Q52", "num": 52, "type": "single_choice", "point": 1, "stem": "What documents include a complete set of organized project records that provide an accurate history of the project?", "options": [{"key": "A", "text": "project archives"}, {"key": "B", "text": "forecasts"}, {"key": "C", "text": "project plans"}, {"key": "D", "text": "project notes"}], "note": "", "answerKey": "A", "answerText": "project archives", "chapter": "第10章 Project Communications Management", "chapterId": "CH10", "chapterNo": 10, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 10.pdf，第42页", "sourceExcerpt": "“Project archives are a complete set of organized project records that provide an accurate history of the project”。", "explanationMd": "**答案：** A. project archives  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 10.pdf`，第42页。  \n**原文摘录：** “Project archives are a complete set of organized project records that provide an accurate history of the project”。  \n**一致性或同义替换说明：** 题干与课件原文一致。", "knowledgePointIds": ["kp_project_archives"], "knowledgePoint": "项目档案", "mnemonic": "Archives = organized historical records。", "trap": "status report 只说明当前状态，不是完整档案。"}, {"id": "Q53", "num": 53, "type": "single_choice", "point": 1, "stem": "Which document addresses where the project stands in terms of meeting scope, time, and cost goals?", "options": [{"key": "A", "text": "technical reports"}, {"key": "B", "text": "status reports"}, {"key": "C", "text": "progress reports"}, {"key": "D", "text": "lessons-learned reports"}], "note": "", "answerKey": "B", "answerText": "status reports", "chapter": "第10章 Project Communications Management", "chapterId": "CH10", "chapterNo": 10, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 10.pdf，第28页", "sourceExcerpt": "“Status reports describe where the project stands at a specific point in time”。", "explanationMd": "**答案：** B. status reports  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 10.pdf`，第28页。  \n**原文摘录：** “Status reports describe where the project stands at a specific point in time”。  \n**一致性或同义替换说明：** 题干 “where the project stands” 与课件原文一致；题干补充的 scope/time/cost goals 是状态报告常见维度。", "knowledgePointIds": ["kp_status_reports"], "knowledgePoint": "状态报告", "mnemonic": "Status = where the project stands now。", "trap": "forecast 是预测未来，progress report 是进展。"}, {"id": "Q54", "num": 54, "type": "single_choice", "point": 1, "stem": "__________ is a testing stage where two or more software units are joined and tested simultaneously.", "options": [{"key": "A", "text": "integration"}, {"key": "B", "text": "unit"}, {"key": "C", "text": "user acceptance"}, {"key": "D", "text": "system"}], "note": "", "answerKey": "A", "answerText": "integration", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "2 + 4", "sharedGroup": "共享选项组 F", "source": "PPT/Chapter 08.pdf，第48页", "sourceExcerpt": "“Integration testing occurs between unit and system testing to test functionally grouped components”。", "explanationMd": "**答案：** A. integration  \n**分类：** 2 + 4  \n**共享选项组：** 共享选项组 F  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 08.pdf`，第48页。  \n**原文摘录：** “Integration testing occurs between unit and system testing to test functionally grouped components”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| two or more software units are joined and tested simultaneously | functionally grouped components | 同义概括 | 集成测试关注组合后的组件/单元是否协同工作。 |\n\n**排除法说明：** unit 是单元测试，system 是整体系统测试，user acceptance 是用户验收；“joined units” 指 integration。", "knowledgePointIds": ["kp_integration_testing"], "knowledgePoint": "集成测试", "mnemonic": "Integration = joined units/components。", "trap": "system testing 是整个系统作为整体测试。"}, {"id": "Q55", "num": 55, "type": "single_choice", "point": 1, "stem": "Which of the following are sub-processes associated with project scope management?", "options": [{"key": "A", "text": "Sequence activities"}, {"key": "B", "text": "Continuous Improvement"}, {"key": "C", "text": "Distribution of information"}, {"key": "D", "text": "Validate work involved"}], "note": "", "answerKey": "D", "answerText": "Validate work involved", "chapter": "第5章 Project Scope Management", "chapterId": "CH05", "chapterNo": 5, "category": "2 + 4", "sharedGroup": "共享选项组 C", "source": "PPT/Chapter 05.pdf，第5页", "sourceExcerpt": "“Validating scope: formalizing acceptance of the project deliverables”。", "explanationMd": "**答案：** D. Validate work involved  \n**分类：** 2 + 4  \n**共享选项组：** 共享选项组 C  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 05.pdf`，第5页。  \n**原文摘录：** “Validating scope: formalizing acceptance of the project deliverables”。  \n**一致性或同义替换说明：**\n\n| 题目/选项表述 | 课件原文表述 | 替换类型 | 判断说明 |\n| ------- | ------ | ---- | ---- |\n| Validate work involved | Validating scope | 同义/不严谨改写 | scope 指项目所包含的工作，选项用 work involved 改写。 |\n| sub-processes associated with project scope management | Project scope management processes include ... Validating scope | 概念对应 | Validate scope 属于范围管理过程。 |\n\n**排除法说明：** 同组选项 A 属进度，B 属质量，C 属沟通，只有 D 对应范围管理。", "knowledgePointIds": ["kp_validate_scope"], "knowledgePoint": "确认范围", "mnemonic": "Validate scope = formal acceptance of deliverables。", "trap": "题目写 Validate work involved，是对 scope 的不严谨改写。"}, {"id": "Q56", "num": 56, "type": "single_choice", "point": 1, "stem": "Which term is used for a significant event on a project that normally has no duration?", "options": [{"key": "A", "text": "milestone"}, {"key": "B", "text": "activity attribute"}, {"key": "C", "text": "activity sequence"}, {"key": "D", "text": "schedule baseline"}], "note": "", "answerKey": "A", "answerText": "milestone", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "1 + 4", "sharedGroup": "共享选项组 H", "source": "PPT/Chapter 06.pdf，第12页", "sourceExcerpt": "“A milestone is a significant event that normally has no duration”。", "explanationMd": "**答案：** A. milestone  \n**分类：** 1 + 4  \n**共享选项组：** 共享选项组 H  \n**依据来源：** 课件；排除法。  \n**具体出处：** `PPT/Chapter 06.pdf`，第12页。  \n**原文摘录：** “A milestone is a significant event that normally has no duration”。  \n**一致性或同义替换说明：** 题干与课件原文一致。  \n**排除法说明：** activity attribute、activity sequence、schedule baseline 都不是“通常无持续时间的重大事件”。", "knowledgePointIds": ["kp_milestone"], "knowledgePoint": "里程碑", "mnemonic": "Milestone = 点，不是任务段。", "trap": "milestone 不是 WBS，也不是网络图；它是关键节点。"}, {"id": "Q57", "num": 57, "type": "single_choice", "point": 1, "stem": "Which reserves allow for future situations that are unpredictable?", "options": [{"key": "A", "text": "Contingency reserves"}, {"key": "B", "text": "Management reserves"}, {"key": "C", "text": "Known unknowns"}, {"key": "D", "text": "Cost baseline reserves"}], "note": "", "answerKey": "B", "answerText": "Management reserves", "chapter": "第7章 Project Cost Management", "chapterId": "CH07", "chapterNo": 7, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 07.pdf，第15页", "sourceExcerpt": "“Management reserves allow for future situations that are unpredictable (sometimes called unknown unknowns)”。", "explanationMd": "**答案：** B. Management reserves  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 07.pdf`，第15页。  \n**原文摘录：** “Management reserves allow for future situations that are unpredictable (sometimes called unknown unknowns)”。  \n**一致性或同义替换说明：** 题干与课件原文一致。", "knowledgePointIds": ["kp_management_reserves"], "knowledgePoint": "管理储备", "mnemonic": "Management reserve = unknown unknowns。", "trap": "contingency reserve 通常对应已识别风险。"}, {"id": "Q58", "num": 58, "type": "single_choice", "point": 1, "stem": "A(n) __________ is a process in which a company solicits select suppliers to submit price bids for the chance to fulfil certain tasks or projects.", "options": [{"key": "A", "text": "RFQ"}, {"key": "B", "text": "WBS"}, {"key": "C", "text": "RFP"}, {"key": "D", "text": "SOW"}], "note": "", "answerKey": "A", "answerText": "RFQ", "chapter": "第12章 Project Procurement Management", "chapterId": "CH12", "chapterNo": 12, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 12.pdf，第27页", "sourceExcerpt": "“Requests for Quotes: Used to solicit quotes or bids from prospective suppliers”。", "explanationMd": "**答案：** A. RFQ  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 12.pdf`，第27页。  \n**原文摘录：** “Requests for Quotes: Used to solicit quotes or bids from prospective suppliers”。  \n**一致性或同义替换说明：** 题干 “solicits select suppliers to submit price bids” 与课件原文高度一致，RFQ 即 Request for Quote。", "knowledgePointIds": ["kp_rfq"], "knowledgePoint": "报价请求 RFQ", "mnemonic": "RFQ = request quotes。", "trap": "看到 price bids / submit quotes 选 RFQ。"}, {"id": "Q59", "num": 59, "type": "single_choice", "point": 1, "stem": "Which technique involves network diagramming and is used primarily to predict total project duration?", "options": [{"key": "A", "text": "Gantt chart"}, {"key": "B", "text": "critical path analysis"}, {"key": "C", "text": "resource breakdown structure"}, {"key": "D", "text": "arrow diagramming method"}], "note": "", "answerKey": "B", "answerText": "critical path analysis", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 06.pdf，第34页", "sourceExcerpt": "“CPM is a network diagramming technique used to predict total project duration”。", "explanationMd": "**答案：** B. critical path analysis  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 06.pdf`，第34页。  \n**原文摘录：** “CPM is a network diagramming technique used to predict total project duration”。  \n**一致性或同义替换说明：** critical path analysis 对应 CPM/critical path method，题干 “network diagramming ... predict total project duration” 与原文一致。", "knowledgePointIds": ["kp_critical_path_analysis"], "knowledgePoint": "关键路径分析", "mnemonic": "CPM = predict total project duration。", "trap": "critical path analysis 是技术，critical path 是路径本身。"}, {"id": "Q60", "num": 60, "type": "single_choice", "point": 1, "stem": "What term is used for the amount of time an activity can be delayed from its early start without delaying the planned project finish date?", "options": [{"key": "A", "text": "total slack"}, {"key": "B", "text": "free float"}, {"key": "C", "text": "backward pass"}, {"key": "D", "text": "forward pass"}], "note": "", "answerKey": "A", "answerText": "total slack", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 06.pdf，第38页", "sourceExcerpt": "“Total slack or total float is the amount of time an activity may be delayed from its early start without delaying the planned project finish date”。", "explanationMd": "**答案：** A. total slack  \n**分类：** 1  \n**共享选项组：** 无  \n**依据来源：** 课件。  \n**具体出处：** `PPT/Chapter 06.pdf`，第38页。  \n**原文摘录：** “Total slack or total float is the amount of time an activity may be delayed from its early start without delaying the planned project finish date”。  \n**一致性或同义替换说明：** 题干与课件原文一致。", "knowledgePointIds": ["kp_total_slack"], "knowledgePoint": "总时差", "mnemonic": "Slack = delay allowed without delaying finish。", "trap": "free slack 与 total slack 不同；题干说不影响 project finish date 是 total slack。"}, {"id": "Q61", "num": 61, "type": "single_choice", "point": 1, "stem": "Which knowledge area involves defining and managing all the work required to complete the project successfully?", "options": [{"key": "A", "text": "Project resource management"}, {"key": "B", "text": "Project scope management"}, {"key": "C", "text": "Project time management"}, {"key": "D", "text": "Project cost management"}], "note": "", "answerKey": "B", "answerText": "Project scope management", "chapter": "第5章 Project Scope Management", "chapterId": "CH05", "chapterNo": 5, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 5.pdf, Slides 5, 42-43; Textbook Chapter 5 pp.183-220", "sourceExcerpt": "Scope management involves defining and managing all the work required to complete the project successfully.", "explanationMd": "**答案：** B. Project scope management\n\n范围管理的核心定义就是\"defining and managing all the work required to complete the project successfully\"，包含六个过程：Plan Scope Management, Collect Requirements, Define Scope, Create WBS, Validate Scope, Control Scope。其他选项：A 资源管理管人力和物资，C 时间管理管进度，D 成本管理管预算。", "knowledgePointIds": [], "knowledgePoint": "范围管理定义", "mnemonic": "看到'defining and managing all the work'→秒选Scope（范围=全部工作的边界）。", "trap": "不要把资源管理(time/cost/resource)的职责跟范围管理混淆。"}, {"id": "Q62", "num": 62, "type": "single_choice", "point": 1, "stem": "An important tool for project scope management is _____.", "options": [{"key": "A", "text": "fast tracking"}, {"key": "B", "text": "a kickoff meeting"}, {"key": "C", "text": "a Gantt chart"}, {"key": "D", "text": "a work breakdown structure"}], "note": "", "answerKey": "D", "answerText": "a work breakdown structure", "chapter": "第5章 Project Scope Management", "chapterId": "CH05", "chapterNo": 5, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 5.pdf, Slides 6, 9, 22; Textbook Chapter 5 pp.183-220", "sourceExcerpt": "WBS is a deliverable-oriented grouping of the work involved in a project that defines its total scope.", "explanationMd": "**答案：** D. a work breakdown structure\n\nWBS（Work Breakdown Structure）是范围管理中最重要的工具，以可交付成果为导向将项目工作逐层分解为工作包。A fast tracking 是时间管理的进度压缩技术，B kickoff meeting 是启动会议，C Gantt chart 是时间管理的进度展示工具。", "knowledgePointIds": [], "knowledgePoint": "WBS（工作分解结构）", "mnemonic": "看到'scope'就找WBS——它是范围管理唯一的标志性工具。", "trap": "Fast tracking 和 Gantt chart 都属于时间管理，kickoff meeting 属于沟通/启动，不要选错。"}, {"id": "Q63", "num": 63, "type": "single_choice", "point": 1, "stem": "Team building exercises and motivation techniques are tools used in _____ management.", "options": [{"key": "A", "text": "procurement"}, {"key": "B", "text": "scope"}, {"key": "C", "text": "resource"}, {"key": "D", "text": "cost"}], "note": "", "answerKey": "C", "answerText": "resource", "chapter": "第9章 Project Resource Management", "chapterId": "CH09", "chapterNo": 9, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 9.pdf, Slides 3-4, 9-10, 38; Textbook Chapter 9 pp.343-388", "sourceExcerpt": "Team building exercises and motivation techniques are core tools in Develop Team and Manage Team processes.", "explanationMd": "**答案：** C. resource\n\n在PMBOK体系中，Resource Management即人力资源管理，包含Develop Team和Manage Team过程。团队建设活动(team building exercises)和激励技巧(motivation techniques)正是这两个过程的核心工具。A Procurement管采购，B Scope管范围，D Cost管成本。", "knowledgePointIds": [], "knowledgePoint": "资源管理（人力资源管理）", "mnemonic": "看到'team'、'motivation'、'people'→选 Resource（管人就是资源管理）。", "trap": "不要把团队建设和激励技术归到采购(procurement)或范围(scope)管理。"}, {"id": "Q64", "num": 64, "type": "single_choice", "point": 1, "stem": "A Gantt chart is a standard format for displaying project schedule information by listing project activities and their corresponding start and finish dates in a ____ format.", "options": [{"key": "A", "text": "calendar"}, {"key": "B", "text": "line graph"}, {"key": "C", "text": "bar graph"}, {"key": "D", "text": "pie chart"}], "note": "", "answerKey": "A", "answerText": "calendar", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 6.pdf, Slides 4, 28, 53; Textbook Chapter 6 pp.221-262", "sourceExcerpt": "A Gantt chart displays project schedule information in a calendar format with horizontal bars.", "explanationMd": "**答案：** A. calendar\n\n甘特图以日历格式(calendar format)展示项目活动的开始和完成日期，横轴是日历时间轴，纵轴是活动列表。虽然包含水平条形，但本质是日历格式。B line graph用于趋势展示，C bar graph是纯条形图，D pie chart是饼图。", "knowledgePointIds": [], "knowledgePoint": "甘特图格式", "mnemonic": "甘特图 = calendar + bar，网络图 = node + arrow，里程碑图 = timeline + mark。", "trap": "甘特图虽然包含条形(bar)，但其本质是日历格式(calendar format)，不要选 bar graph。"}, {"id": "Q65", "num": 65, "type": "single_choice", "point": 1, "stem": "Which of the following statements are TRUE?", "options": [{"key": "A", "text": "The question, \"What unique product, service, or result does the customer or sponsor expect from the project?\" is an example of a scope constraint."}, {"key": "B", "text": "The question, \"What is the project's schedule?\" is an example of a time constraint."}, {"key": "C", "text": "The quadruple constraint of project management includes quality, scope, time, and cost constraints."}, {"key": "D", "text": "All of the options stated"}], "note": "", "answerKey": "D", "answerText": "All of the options stated", "chapter": "第1章 Introduction to Project Management", "chapterId": "CH01", "chapterNo": 1, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 1.pdf, Slides 6-8, 11; Textbook Chapter 1 pp.1-42", "sourceExcerpt": "The quadruple constraint includes quality, scope, time, and cost. The triple constraint is scope, time, cost.", "explanationMd": "**答案：** D. All of the options stated\n\nA正确：询问客户期望的独特产品/服务/结果是在界定范围约束。B正确：询问项目进度计划是时间约束。C正确：四重约束在经典三重约束(scope+time+cost)基础上增加了质量(quality)维度。三条全对。", "knowledgePointIds": [], "knowledgePoint": "四重约束 (Quadruple Constraint)", "mnemonic": "四重约束 = scope + time + cost + quality。三条全对选All。", "trap": "Quadruple constraint 不是 pentuple constraint——不要凭空添加 risk 或 resources。"}, {"id": "Q66", "num": 66, "type": "single_choice", "point": 1, "stem": "Which of the following is an example of external stakeholders for an organization?", "options": [{"key": "A", "text": "Top managers"}, {"key": "B", "text": "Functional managers"}, {"key": "C", "text": "Employees"}, {"key": "D", "text": "Competitors"}], "note": "", "answerKey": "D", "answerText": "Competitors", "chapter": "第13章 Project Stakeholder Management", "chapterId": "CH13", "chapterNo": 13, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 13.pdf, Slides 5-8, 10; Textbook Chapter 13 pp.495-530", "sourceExcerpt": "External stakeholders include competitors, suppliers, government agencies, and customers.", "explanationMd": "**答案：** D. Competitors\n\n内部干系人(internal stakeholders)包括 top managers, functional managers, employees 等在组织内部的人。外部干系人(external stakeholders)包括 competitors, suppliers, government agencies, customers 等在组织外部的个人或群体。", "knowledgePointIds": [], "knowledgePoint": "外部干系人 vs 内部干系人", "mnemonic": "公司围墙内外法则——围墙里面(internal)的是员工/经理/高管，围墙外面(external)的是客户/供应商/政府/竞争者。", "trap": "Competitors 虽影响项目但从不在组织内部工作，必是 external。不要把 top managers 归到外部。"}, {"id": "Q67", "num": 67, "type": "single_choice", "point": 1, "stem": "Which of the following is true of the project life cycle?", "options": [{"key": "A", "text": "In the early phases of a project life cycle, resource needs are usually lowest."}, {"key": "B", "text": "In the later phases of the project life cycle, the level of uncertainty is usually the highest."}, {"key": "C", "text": "It is much more expensive to make major changes to a project during the earlier phases than the latter phases."}, {"key": "D", "text": "More resources are usually needed during the initial phases of a project than during the middle or final phases."}], "note": "", "answerKey": "A", "answerText": "In the early phases of a project life cycle, resource needs are usually lowest.", "chapter": "第2章 Project Management and Information Technology Context", "chapterId": "CH02", "chapterNo": 2, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 2.pdf, Slides 29-32; Textbook Chapter 2 pp.43-78", "sourceExcerpt": "In early phases, resource needs are lowest, uncertainty is highest, and cost of changes is lowest.", "explanationMd": "**答案：** A\n\nA正确：项目早期资源投入最低（只有少数人做规划）。B错误：后期不确定性应是最低。C错误：早期变更最便宜，后期变更代价最大。D错误：中期（执行阶段）资源需求最高。", "knowledgePointIds": [], "knowledgePoint": "项目生命周期特征", "mnemonic": "早期→低资源+高不确定性+低变更成本；后期→高资源+低不确定性+高变更成本。两个'最低'在早期（资源、变更成本），一个'最高'在早期（不确定性）。", "trap": "后期不确定性是'最低'而非'最高'；早期变更成本是'最低'而非'最高'。"}, {"id": "Q68", "num": 68, "type": "single_choice", "point": 1, "stem": "Which systems development life cycle model assumes that requirements will remain stable after they are defined?", "options": [{"key": "A", "text": "Spiral life cycle"}, {"key": "B", "text": "Waterfall life cycle"}, {"key": "C", "text": "Prototyping life cycle"}, {"key": "D", "text": "RAD life cycle"}], "note": "", "answerKey": "B", "answerText": "Waterfall life cycle", "chapter": "第2章 Project Management and Information Technology Context", "chapterId": "CH02", "chapterNo": 2, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 2.pdf, Slides 25-26, 38; Textbook Chapter 2 pp.43-78", "sourceExcerpt": "The Waterfall model assumes requirements are frozen and will remain stable after definition.", "explanationMd": "**答案：** B. Waterfall life cycle\n\n瀑布模型是最经典、最线性的SDLC模型，核心假设是'需求在定义之后保持稳定'。阶段严格顺序执行，一旦进入下一阶段就不返回修改。A Spiral通过反复迭代降低风险，C Prototyping通过原型发现需求，D RAD强调快速迭代和用户反馈。", "knowledgePointIds": [], "knowledgePoint": "瀑布模型 (Waterfall)", "mnemonic": "看到'requirements remain stable'→选 Waterfall。反之看到'iterative'、'evolving requirements'→选 Spiral/Agile/Prototyping。", "trap": "Waterfall假设需求冻结不变，Spiral/Prototyping/RAD都假设需求可能演变。不要搞反。"}, {"id": "Q69", "num": 69, "type": "single_choice", "point": 1, "stem": "Which statement best describes outsourcing?", "options": [{"key": "A", "text": "An organization selling its products in a market outside its domestic market"}, {"key": "B", "text": "An organization's acquisition of goods and services from an outside source"}, {"key": "C", "text": "An organization setting up manufacturing and retailing facilities in a new country"}, {"key": "D", "text": "An organization's use of virtual teams with employees located in different countries"}], "note": "", "answerKey": "B", "answerText": "An organization's acquisition of goods and services from an outside source", "chapter": "第12章 Project Procurement Management", "chapterId": "CH12", "chapterNo": 12, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 12.pdf, Slides 3, 5, 7-8; Textbook Chapter 12 pp.465-494", "sourceExcerpt": "Outsourcing is an organization's acquisition of goods and services from an outside source.", "explanationMd": "**答案：** B\n\nOutsourcing的精确定义是：组织从外部来源获取商品和服务(acquisition of goods and services from an outside source)。A描述的是出口销售，C描述的是海外设厂(FDI)，D描述的是虚拟团队。关键是'从外部获取'而非自己内部生产。", "knowledgePointIds": [], "knowledgePoint": "外包 (Outsourcing)", "mnemonic": "外包核心 = 自己不干，让别人干。Outsourcing 是从外部来源获取商品和服务。", "trap": "Outsourcing(从外部获取) ≠ Offshoring(搬到国外) ≠ Exporting(向海外销售) ≠ Virtual teams(远程团队)。"}, {"id": "Q70", "num": 70, "type": "single_choice", "point": 1, "stem": "What is the main purpose of project plans?", "options": [{"key": "A", "text": "schedule management plans"}, {"key": "B", "text": "define project scope"}, {"key": "C", "text": "estimate activity resources"}, {"key": "D", "text": "guide project execution"}], "note": "", "answerKey": "D", "answerText": "guide project execution", "chapter": "第4章 Project Integration Management", "chapterId": "CH04", "chapterNo": 4, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 4.pdf, Slides 6, 32-36, 38; Textbook Chapter 4 pp.137-182", "sourceExcerpt": "The main purpose of a project management plan is to guide project execution.", "explanationMd": "**答案：** D. guide project execution\n\n项目管理计划(Project Management Plan)整合所有辅助计划，最主要目的是指导项目执行(guide project execution)。A、B、C 都是计划中的某项内容或子计划，不是整体计划的核心目的。", "knowledgePointIds": [], "knowledgePoint": "项目计划的目的", "mnemonic": "Charter = 授权(authorize/initiate)，Plan = 指导执行(guide execution)。看到'main purpose of project plans'→选 guide execution。", "trap": "不要把子计划(schedule management plans)的目的当成整个项目计划的目的。"}, {"id": "Q71", "num": 71, "type": "single_choice", "point": 1, "stem": "Which process involves gaining stakeholder and customer acceptance of the final products and services and bringing the project, or project phase, to an orderly end?", "options": [{"key": "A", "text": "executing"}, {"key": "B", "text": "closing"}, {"key": "C", "text": "planning"}, {"key": "D", "text": "monitoring"}], "note": "", "answerKey": "B", "answerText": "closing", "chapter": "第3章 The Project Management Process Groups", "chapterId": "CH03", "chapterNo": 3, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 3.pdf, Slides 4, 17-18; Textbook Chapter 3 pp.79-136", "sourceExcerpt": "The closing process group gains stakeholder and customer acceptance and brings the project to an orderly end.", "explanationMd": "**答案：** B. closing\n\nClosing过程组的核心任务：获得干系人和客户对最终产品和服务的验收(gain acceptance)、归档文档、总结经验教训、释放资源、使项目有序结束(orderly end)。题干中'gaining stakeholder and customer acceptance'和'orderly end'是closing的标志性表述。", "knowledgePointIds": [], "knowledgePoint": "收尾过程组 (Closing Process Group)", "mnemonic": "看到'acceptance + orderly end'→选 Closing。", "trap": "Executing是把计划变成工作，Planning是制定计划，Monitoring是跟踪审查。不要把收尾跟执行搞混。"}, {"id": "Q72", "num": 72, "type": "single_choice", "point": 1, "stem": "Which method of communication is likely to be most effective for conveying sensitive or important information?", "options": [{"key": "A", "text": "short face-to-face meetings"}, {"key": "B", "text": "e-mails"}, {"key": "C", "text": "telephone conversations"}, {"key": "D", "text": "reading reports from other team members"}], "note": "", "answerKey": "A", "answerText": "short face-to-face meetings", "chapter": "第10章 Project Communications Management", "chapterId": "CH10", "chapterNo": 10, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 10.pdf, Slides 11, 24; Textbook Chapter 10 pp.389-424", "sourceExcerpt": "Face-to-face meetings are the richest communication channel, best for sensitive or important information.", "explanationMd": "**答案：** A. short face-to-face meetings\n\n根据媒介丰富度理论(Media Richness Theory)，面对面沟通是最丰富的渠道——同时传递语言和非语言信息（眼神、肢体语言、语调）、可即时反馈和澄清、建立信任和情感连接。Email 缺乏非语言线索易于误解，telephone 有语音但缺视觉线索，written report 是单向无即时反馈。", "knowledgePointIds": [], "knowledgePoint": "媒介丰富度理论 (Media Richness Theory)", "mnemonic": "越敏感的沟通→越丰富的渠道。Sensitive/important → face-to-face。Routine/documented → email/report。", "trap": "Email缺乏非语言线索易于误解，telephone有语音但缺视觉线索。敏感信息不要选email或report。"}, {"id": "Q73", "num": 73, "type": "single_choice", "point": 1, "stem": "A team has 10 communication channels between its various members. Using the formula for calculating the number of communication channels, it can be deduced that the team has _____ members.", "options": [{"key": "A", "text": "2"}, {"key": "B", "text": "3"}, {"key": "C", "text": "5"}, {"key": "D", "text": "10"}], "note": "", "answerKey": "C", "answerText": "5", "chapter": "第10章 Project Communications Management", "chapterId": "CH10", "chapterNo": 10, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 10.pdf, Slides 8-10; Textbook Chapter 10 pp.389-424", "sourceExcerpt": "Communication channels = n(n-1)/2. With 10 channels, n=5 members (5×4/2=10).", "explanationMd": "**答案：** C. 5\n\n沟通渠道数 = n(n-1)/2。已知渠道数 = 10：n(n-1)/2 = 10 → n(n-1) = 20 → n = 5。验证：5×4/2=10。A n=2→1条，B n=3→3条，D n=10→45条。", "knowledgePointIds": [], "knowledgePoint": "沟通渠道公式 n(n-1)/2", "mnemonic": "n(n-1)/2 = 10 → n(n-1) = 20 → n = 5。记不住公式就记住5人=10条渠道，10人=45条渠道。", "trap": "不要把n=10代入公式得到45条渠道当成答案，题目问的是'有多少成员'不是'有多少渠道'。"}, {"id": "Q74", "num": 74, "type": "single_choice", "point": 1, "stem": "As the number of people involved in a project _____, the complexity of communications _____.", "options": [{"key": "A", "text": "increases, decreases"}, {"key": "B", "text": "decreases, increases"}, {"key": "C", "text": "increases, stays constant"}, {"key": "D", "text": "increases, increases"}], "note": "", "answerKey": "D", "answerText": "increases, increases", "chapter": "第10章 Project Communications Management", "chapterId": "CH10", "chapterNo": 10, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 10.pdf, Slide 18; Textbook Chapter 10 pp.389-424", "sourceExcerpt": "As more people are involved, communication complexity increases nonlinearly (n(n-1)/2).", "explanationMd": "**答案：** D. increases, increases\n\n沟通复杂度与参与人数成正比：人数越多，沟通路径越多，沟通越复杂。由公式n(n-1)/2可知，沟通渠道数随人数呈平方级增长。4人团队只有6条路径，8人团队有28条。", "knowledgePointIds": [], "knowledgePoint": "沟通复杂度与团队规模", "mnemonic": "人越多沟通越复杂——n(n-1)/2呈平方级增长。人数翻倍，沟通复杂度增加数倍。", "trap": "沟通复杂度随人数增加而增加，不是此消彼长的关系。不要选'increases, decreases'。"}, {"id": "Q75", "num": 75, "type": "single_choice", "point": 1, "stem": "Which document describes where the project stands at a specific point in time?", "options": [{"key": "A", "text": "progress reports"}, {"key": "B", "text": "status reports"}, {"key": "C", "text": "forecasts"}, {"key": "D", "text": "lessons-learned reports"}], "note": "", "answerKey": "B", "answerText": "status reports", "chapter": "第10章 Project Communications Management", "chapterId": "CH10", "chapterNo": 10, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 10.pdf, Slide 29; Textbook Chapter 10 pp.389-424", "sourceExcerpt": "Status reports describe where the project stands at a specific point in time.", "explanationMd": "**答案：** B. status reports\n\nStatus Report(状态报告)描述项目在特定时间点的状态快照——'此刻是什么情况'。A Progress Report描述某一时段内完成了什么(动态回顾)。C Forecast基于历史数据预测未来。D Lessons-learned Report总结过去经验教训。", "knowledgePointIds": [], "knowledgePoint": "状态报告 (Status Report)", "mnemonic": "Status→状态→'at a point'→快照(standing)；Progress→进展→'during a period'→回顾(accomplished)；Forecast→预测→'predicts future'→前瞻。", "trap": "Status report是'此刻的快照'(at a specific point in time)，Progress report是'过去一段干了什么'(during a certain period)。不要互换。"}, {"id": "Q76", "num": 76, "type": "single_choice", "point": 1, "stem": "Which document describes what the project team has accomplished during a certain period?", "options": [{"key": "A", "text": "progress reports"}, {"key": "B", "text": "status reports"}, {"key": "C", "text": "forecasts"}, {"key": "D", "text": "lessons-learned reports"}], "note": "", "answerKey": "A", "answerText": "progress reports", "chapter": "第10章 Project Communications Management", "chapterId": "CH10", "chapterNo": 10, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 10.pdf, Slide 29; Textbook Chapter 10 pp.389-424", "sourceExcerpt": "Progress reports describe what the project team has accomplished during a certain period.", "explanationMd": "**答案：** A. progress reports\n\nProgress Report(进展报告)描述项目团队在某一时段内完成了什么工作——'这段时间干了什么'，是动态回顾。B Status Report是特定时间点的快照。C Forecast是前瞻预测。", "knowledgePointIds": [], "knowledgePoint": "进展报告 (Progress Report)", "mnemonic": "Progress→进展→'during a period'→回顾(accomplished)。记住Q15-Q17三连：Status=快照、Progress=回顾、Forecast=前瞻。", "trap": "Progress report是'过去一段完成了什么'，Status report是'此刻状态是什么'。看准题干中的'accomplished during a certain period'。"}, {"id": "Q77", "num": 77, "type": "single_choice", "point": 1, "stem": "Which document predicts future project status and progress based on past information and trends?", "options": [{"key": "A", "text": "progress reports"}, {"key": "B", "text": "status reports"}, {"key": "C", "text": "forecasts"}, {"key": "D", "text": "project updates"}], "note": "", "answerKey": "C", "answerText": "forecasts", "chapter": "第10章 Project Communications Management", "chapterId": "CH10", "chapterNo": 10, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 10.pdf, Slide 29; Textbook Chapter 10 pp.389-424", "sourceExcerpt": "Forecasts predict future project status and progress based on past information and trends.", "explanationMd": "**答案：** C. forecasts\n\nForecast(预测)基于挣值管理等历史数据外推未来的项目状态和进展——'根据目前走势，接下来会怎样'。A Progress Report回顾过去，B Status Report展示当前快照，D Project Updates不是标准报告类型。", "knowledgePointIds": [], "knowledgePoint": "预测 (Forecast)", "mnemonic": "Forecast→预测→'predicts future'→基于历史数据和趋势推算未来。三份报告就像开车：Status=即时速度，Progress=已开里程，Forecast=预计到达时间。", "trap": "Forecast不是'project updates'(项目更新)，后者是泛指更新信息不是标准报告类型。"}, {"id": "Q78", "num": 78, "type": "single_choice", "point": 1, "stem": "Scope, time and cost goals in order of importance can be ranked on a(n) _____.", "options": [{"key": "A", "text": "requirements traceability matrix"}, {"key": "B", "text": "expectations management matrix"}, {"key": "C", "text": "responsibility assignment matrix"}, {"key": "D", "text": "probability matrix"}], "note": "", "answerKey": "B", "answerText": "expectations management matrix", "chapter": "第5章 Project Scope Management", "chapterId": "CH05", "chapterNo": 5, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 5.pdf, Slide 39; Textbook Chapter 5 pp.183-220", "sourceExcerpt": "An expectations management matrix ranks scope, time, and cost goals in order of importance.", "explanationMd": "**答案：** B. expectations management matrix\n\nExpectations Management Matrix用于对项目的范围、时间和成本目标按重要性排序，帮助在权衡决策时有明确优先级。A RTM追踪需求来源和状态，C RAM定义谁负责什么工作，D Probability Matrix用于风险评估。", "knowledgePointIds": [], "knowledgePoint": "期望管理矩阵 (Expectations Management Matrix)", "mnemonic": "看到'scope, time, cost...ranked in order of importance'→找 Expectations Management Matrix。", "trap": "不要跟Requirements Traceability Matrix(追踪需求)或Responsibility Assignment Matrix(分配责任)混淆。"}, {"id": "Q79", "num": 79, "type": "single_choice", "point": 1, "stem": "What is a table that lists requirements, their various attributes, and the status of the requirements to ensure that all are addressed referred to as?", "options": [{"key": "A", "text": "requirements traceability matrix"}, {"key": "B", "text": "Gantt chart"}, {"key": "C", "text": "state transition table"}, {"key": "D", "text": "entity-attribute-value model"}], "note": "", "answerKey": "A", "answerText": "requirements traceability matrix", "chapter": "第5章 Project Scope Management", "chapterId": "CH05", "chapterNo": 5, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 5.pdf, Slides 15-17; Textbook Chapter 5 pp.183-220", "sourceExcerpt": "A Requirements Traceability Matrix lists requirements, their attributes, and status to ensure all are addressed.", "explanationMd": "**答案：** A. requirements traceability matrix\n\nRTM(需求跟踪矩阵)列出各项需求及其属性(优先级、来源、状态等)，确保每个需求都被追踪到对应的可交付成果和测试用例。B Gantt chart是进度工具，C State transition table是系统设计工具，D EAV model是数据建模概念。", "knowledgePointIds": [], "knowledgePoint": "需求跟踪矩阵 (RTM)", "mnemonic": "看到'requirements'+'table'+'status'+'attributes'→ RTM。RTM是Collect Requirements过程的关键输出。", "trap": "RTM是项目管理工具，不是State transition table(系统设计)或Entity-attribute-value model(数据建模)。"}, {"id": "Q80", "num": 80, "type": "single_choice", "point": 1, "stem": "What is the main technique used in creating a WBS, which involves subdividing project deliverables into smaller pieces?", "options": [{"key": "A", "text": "conglomeration"}, {"key": "B", "text": "accumulation"}, {"key": "C", "text": "decomposition"}, {"key": "D", "text": "catalyzation"}], "note": "", "answerKey": "C", "answerText": "decomposition", "chapter": "第5章 Project Scope Management", "chapterId": "CH05", "chapterNo": 5, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 5.pdf, Slides 6, 9, 22; Textbook Chapter 5 pp.183-220", "sourceExcerpt": "Decomposition is subdividing project deliverables into smaller, more manageable components.", "explanationMd": "**答案：** C. decomposition\n\nDecomposition(分解法)是创建WBS的核心技术，将项目可交付成果逐层细分为更小、更易管理的组件(工作包)。A Conglomeration是聚合(反义词)，B Accumulation是积累，D Catalyzation是催化(非PM术语)。", "knowledgePointIds": [], "knowledgePoint": "分解法 (Decomposition)", "mnemonic": "'subdividing'+'smaller pieces'→ Decomposition。这个词在范围管理中是核心关键词。", "trap": "Conglomeration是聚合(反义)，Accumulation是积累，Catalyzation是催化——都不是项目管理标准术语。"}, {"id": "Q81", "num": 81, "type": "single_choice", "point": 1, "stem": "Which approach for constructing a WBS starts with the largest items of the project and breaks them into subordinate items?", "options": [{"key": "A", "text": "analogy"}, {"key": "B", "text": "bottom-up"}, {"key": "C", "text": "top-down"}, {"key": "D", "text": "mind mapping"}], "note": "", "answerKey": "C", "answerText": "top-down", "chapter": "第5章 Project Scope Management", "chapterId": "CH05", "chapterNo": 5, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 5.pdf, Slides 3, 6, 9, 22; Textbook Chapter 5 pp.183-220", "sourceExcerpt": "The top-down approach starts with the largest items and breaks them into subordinate items.", "explanationMd": "**答案：** C. top-down\n\nTop-down approach(自上而下法)从项目最大的可交付成果开始，逐步分解为从属的更小组件。A Analogy用类似项目WBS做模板，B Bottom-up从底层任务向上聚合(方向相反)，D Mind mapping以发散思维展开。", "knowledgePointIds": [], "knowledgePoint": "自上而下法 (Top-down Approach)", "mnemonic": "Top-down = 从最大项开始 → 逐层分解到从属项。Bottom-up是反过来的——从底层任务向上聚合。", "trap": "看到'starts with the largest items'就是top-down，bottom-up是从最底层具体任务开始聚合。"}, {"id": "Q82", "num": 82, "type": "single_choice", "point": 1, "stem": "Which is recommended for the creation of a good WBS?", "options": [{"key": "A", "text": "Any WBS item should be the responsibility of all the people working on it."}, {"key": "B", "text": "A unit of work should appear at only one place in the WBS."}, {"key": "C", "text": "Each WBS item should be created assuming that the requirements are inflexible."}, {"key": "D", "text": "The work content of a WBS item is independent of the WBS items below it."}], "note": "", "answerKey": "B", "answerText": "A unit of work should appear at only one place in the WBS.", "chapter": "第5章 Project Scope Management", "chapterId": "CH05", "chapterNo": 5, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 5.pdf, Slides 6, 9, 22, 28; Textbook Chapter 5 pp.183-220", "sourceExcerpt": "A unit of work should appear at only one place in the WBS (uniqueness principle).", "explanationMd": "**答案：** B\n\n良好WBS的核心原则——唯一性原则：每个工作单元只出现在WBS的一个位置(A unit of work should appear at only one place in the WBS)。如果同一工作出现在两处，将导致重复计算和权责不清。A错误：每个WBS项应由一个人负责而非所有人。C错误：WBS应适应需求变化。D错误：父项内容=下层所有工作包之和(非独立)。", "knowledgePointIds": [], "knowledgePoint": "WBS 100%规则与唯一性原则", "mnemonic": "好的WBS：每个工作单元只出现一次(唯一性)；每个WBS项由一个人负责(责任制)；可适应需求变化；父项=子项之和。", "trap": "A错在'all people'——应该由一个人或一个团队负责。'If everyone is responsible, no one is responsible.'"}, {"id": "Q83", "num": 83, "type": "single_choice", "point": 1, "stem": "Which process involves developing a working replica of the system or some aspect of the system?", "options": [{"key": "A", "text": "Prototyping"}, {"key": "B", "text": "Variance"}, {"key": "C", "text": "Decomposition"}, {"key": "D", "text": "Use case modeling"}], "note": "", "answerKey": "A", "answerText": "Prototyping", "chapter": "第5章 Project Scope Management", "chapterId": "CH05", "chapterNo": 5, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 5.pdf, Slides 15, 40; Textbook Chapter 5 pp.183-220", "sourceExcerpt": "Prototyping involves developing a working replica of the system to validate requirements.", "explanationMd": "**答案：** A. Prototyping\n\nPrototyping(原型法)开发系统或其某个方面的可工作复制品(working replica)，帮助用户和开发团队更清晰地理解需求、验证设计。B Variance是偏差(计划vs实际)，C Decomposition是分解法，D Use case modeling描述用户与系统的交互场景。", "knowledgePointIds": [], "knowledgePoint": "原型法 (Prototyping)", "mnemonic": "'working replica'是prototyping的标志性关键词。原型法让用户'看到和用上'未来系统的样子。", "trap": "不要把Variance(偏差)、Decomposition(分解)跟Prototyping(制作工作复制品)搞混。"}, {"id": "Q84", "num": 84, "type": "single_choice", "point": 1, "stem": "Which of the following statements are TRUE?", "options": [{"key": "A", "text": "The scope baseline includes the approved project scope statement and its associated WBS and WBS dictionary."}, {"key": "B", "text": "A WBS is a deliverable-oriented grouping of the work involved in a project that defines its total scope."}, {"key": "C", "text": "Project scope management includes the processes involved in defining and controlling what work is or is not included in a project."}, {"key": "D", "text": "All of the options stated"}], "note": "", "answerKey": "D", "answerText": "All of the options stated", "chapter": "第5章 Project Scope Management", "chapterId": "CH05", "chapterNo": 5, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 5.pdf, Slides 6, 22, 31; Textbook Chapter 5 pp.183-220", "sourceExcerpt": "Scope Baseline = approved scope statement + WBS + WBS dictionary. WBS is deliverable-oriented.", "explanationMd": "**答案：** D. All of the options stated\n\nA正确：Scope Baseline由scope statement + WBS + WBS dictionary三部分组成。B正确：WBS以可交付成果为导向(deliverable-oriented)定义总范围。C正确：范围管理包含定义和控制项目包含/不包含哪些工作的过程。三条全对。", "knowledgePointIds": [], "knowledgePoint": "范围基线与WBS", "mnemonic": "Scope Baseline = scope statement + WBS + WBS dictionary。WBS是deliverable-oriented的。三条全对选All。", "trap": "WBS不是活动清单(活动清单是时间管理的输出)——WBS是'要交付什么'的分解，不是'怎么干'的分解。"}, {"id": "Q85", "num": 85, "type": "single_choice", "point": 1, "stem": "Which of the following statements are FALSE?", "options": [{"key": "A", "text": "When using project management software, estimates of work time should be entered only at the work package level; the rest of the WBS items are just groupings or summary tasks."}, {"key": "B", "text": "A work package is a task at the highest level of the WBS."}, {"key": "C", "text": "A WBS dictionary is a document that describes detailed information about each WBS item."}, {"key": "D", "text": "Scope creep is the tendency for project scope to keep getting bigger and bigger."}], "note": "", "answerKey": "B", "answerText": "A work package is a task at the highest level of the WBS.", "chapter": "第5章 Project Scope Management", "chapterId": "CH05", "chapterNo": 5, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 5.pdf, Slides 9, 22, 28, 31; Textbook Chapter 5 pp.183-220", "sourceExcerpt": "A work package is a task at the lowest level of the WBS, not the highest level.", "explanationMd": "**答案：** B\n\nB是FALSE：工作包是WBS的最底层(lowest level)，不是最高层。WBS层级：Project → Deliverables → Sub-deliverables → Work Packages(最底层)。A TRUE：工时估算只输入在工作包层级。C TRUE：WBS词典描述每个WBS元素的详细信息。D TRUE：Scope creep是范围不断扩大的倾向。", "knowledgePointIds": [], "knowledgePoint": "工作包 (Work Package)", "mnemonic": "Work package是WBS的最底层(lowest level)，不是最高层。最高层是项目名称(Level 0)。题目要选FALSE的。", "trap": "本题要选FALSE！Work package = lowest level of WBS，B说成highest level正好反了。A/C/D都是TRUE的。"}, {"id": "Q86", "num": 86, "type": "single_choice", "point": 1, "stem": "In project schedule management, which process generates the main outputs of an activity list, activity attributes, and a milestone list?", "options": [{"key": "A", "text": "sequencing activities"}, {"key": "B", "text": "defining activities"}, {"key": "C", "text": "resource estimating activities"}, {"key": "D", "text": "estimating activity durations"}], "note": "", "answerKey": "B", "answerText": "defining activities", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 6.pdf, Slides 8, 12; Textbook Chapter 6 pp.221-262", "sourceExcerpt": "Define Activities produces activity list, activity attributes, and milestone list as outputs.", "explanationMd": "**答案：** B. defining activities\n\nDefine Activities过程以WBS为输入，将工作包进一步分解为具体活动，输出：Activity List(活动清单)、Activity Attributes(活动属性)、Milestone List(里程碑清单)。A Sequencing产生活动顺序/网络图，C和D以activity list为输入而非产出。", "knowledgePointIds": [], "knowledgePoint": "定义活动 (Define Activities)", "mnemonic": "看到'activity list + milestone list + activity attributes'三个同时出现→ Define Activities。", "trap": "Sequencing Activities以activity list为输入(非输出)，Estimating以activity list为输入。只有Define Activities产生活动清单。"}, {"id": "Q87", "num": 87, "type": "single_choice", "point": 1, "stem": "During which relationship is the \"from\" activity unable start until the \"to\" activity is started?", "options": [{"key": "A", "text": "start-to-start"}, {"key": "B", "text": "finish-to-finish"}, {"key": "C", "text": "finish-to-start"}, {"key": "D", "text": "start-to-finish"}], "note": "", "answerKey": "A", "answerText": "start-to-start", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 6.pdf, Slides 14-16; Textbook Chapter 6 pp.221-262", "sourceExcerpt": "Start-to-Start (SS): the 'from' activity cannot start until the 'to' activity is started.", "explanationMd": "**答案：** A. start-to-start\n\nStart-to-Start(SS)依赖关系：from活动必须在to活动开始之后才能开始。即前置活动的开始依赖于后继活动的开始。FS(最常见)：from完成to才能开始。FF：from完成to才能完成。SF(最罕见)：from开始to才能完成。", "knowledgePointIds": [], "knowledgePoint": "依赖关系：Start-to-Start (SS)", "mnemonic": "缩写名称就是'from的什么依赖于to的什么'——SS = from的Start依赖于to的Start。", "trap": "四种依赖：FS最常见，SS并行起步，FF同时收尾，SF最罕见。不要混。"}, {"id": "Q88", "num": 88, "type": "single_choice", "point": 1, "stem": "Which is true of a finish-to-finish dependency?", "options": [{"key": "A", "text": "It is a dependency in which the \"from\" activity cannot start until the \"to\" activity or successor is started."}, {"key": "B", "text": "It is a dependency in which the \"from\" activity must finish before the \"to\" activity or successor can start."}, {"key": "C", "text": "It is a dependency in which the \"from\" activity must be finished before the \"to\" activity can be finished."}, {"key": "D", "text": "It is a dependency in which the \"from\" activity must start before the \"to\" activity can be finished."}], "note": "", "answerKey": "C", "answerText": "It is a dependency in which the \"from\" activity must be finished before the \"to\" activity can be finished.", "chapter": "第6章 Project Time Management", "chapterId": "CH06", "chapterNo": 6, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 6.pdf, Slides 14-16; Textbook Chapter 6 pp.221-262", "sourceExcerpt": "Finish-to-Finish (FF): the 'from' activity must finish before the 'to' activity can finish.", "explanationMd": "**答案：** C\n\nFinish-to-Finish(FF)依赖关系：from活动必须完成之后，to活动才能完成。两者可同时进行，但前者的完成是后者完成的条件。A描述的是SS，B描述的是FS，D描述的是SF。", "knowledgePointIds": [], "knowledgePoint": "依赖关系：Finish-to-Finish (FF)", "mnemonic": "FF = from的Finish决定to的Finish——'两个要同时结束，前一个不能比后一个先完成'。", "trap": "A描述的是SS，B描述的是FS，D描述的是SF。四种依赖各对应一个选项描述，要逐一对应。"}, {"id": "Q89", "num": 89, "type": "single_choice", "point": 1, "stem": "Which process results in a cost baseline as a main output?", "options": [{"key": "A", "text": "cost controlling"}, {"key": "B", "text": "cost estimating"}, {"key": "C", "text": "cost budgeting"}, {"key": "D", "text": "cost planning"}], "note": "", "answerKey": "C", "answerText": "cost budgeting", "chapter": "第7章 Project Cost Management", "chapterId": "CH07", "chapterNo": 7, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 7.pdf, Slides 16, 28, 30, 42; Textbook Chapter 7 pp.263-298", "sourceExcerpt": "Cost Budgeting (Determine Budget) produces the cost baseline as a main output.", "explanationMd": "**答案：** C. cost budgeting\n\n成本基线(Cost Baseline)是Cost Budgeting(确定预算)过程的主要输出，是经过批准的分阶段预算，用于衡量和监控成本绩效。A Cost Controlling产出绩效信息和变更请求，B Cost Estimating产出活动成本估算，D Cost Planning产出Cost Management Plan。", "knowledgePointIds": [], "knowledgePoint": "成本预算 (Cost Budgeting)", "mnemonic": "Estimating=单个估算，Budgeting=汇总形成基线，Controlling=监控偏差。看到'baseline'想到budgeting/确定预算。", "trap": "Cost Planning产出的是Cost Management Plan(方法指南)，不是cost baseline。Cost budgeting才产出cost baseline。"}, {"id": "Q90", "num": 90, "type": "single_choice", "point": 1, "stem": "Which method is used for determining the estimated annual costs and benefits for a project?", "options": [{"key": "A", "text": "Critical path analysis"}, {"key": "B", "text": "Cash flow analysis"}, {"key": "C", "text": "Present value analysis"}, {"key": "D", "text": "Requirements analysis"}], "note": "", "answerKey": "B", "answerText": "Cash flow analysis", "chapter": "第7章 Project Cost Management", "chapterId": "CH07", "chapterNo": 7, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 7.pdf, Slide 10; Textbook Chapter 7 pp.263-298", "sourceExcerpt": "Cash flow analysis determines the estimated annual costs and benefits for a project.", "explanationMd": "**答案：** B. Cash flow analysis\n\nCash Flow Analysis(现金流分析)是确定项目每年估算成本和收益的方法。它追踪项目整个生命周期中的资金流入和流出。A Critical path analysis是进度管理工具，C Present value analysis将未来现金流折现到现值，D Requirements analysis是范围管理。", "knowledgePointIds": [], "knowledgePoint": "现金流分析 (Cash Flow Analysis)", "mnemonic": "看到'annual costs and benefits'→ Cash flow analysis。Cash flow关注'一年一年看'，NPV关注'全部折算到今天'。", "trap": "Critical path analysis是进度管理工具(非成本收益分析)，Present value analysis是cash flow的后续折现处理。"}, {"id": "Q91", "num": 91, "type": "single_choice", "point": 1, "stem": "Which statement is true regarding indirect costs?", "options": [{"key": "A", "text": "directly related to performing the project."}, {"key": "B", "text": "those that cannot be allocated to projects."}, {"key": "C", "text": "those that can be easily controlled by managers."}, {"key": "D", "text": "not directly related to the products or services of a project."}], "note": "", "answerKey": "D", "answerText": "not directly related to the products or services of a project.", "chapter": "第7章 Project Cost Management", "chapterId": "CH07", "chapterNo": 7, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 7.pdf, Slide 13; Textbook Chapter 7 pp.263-298", "sourceExcerpt": "Indirect costs are not directly related to the products or services of a project.", "explanationMd": "**答案：** D\n\nIndirect costs(间接成本)不与特定项目的产品或服务直接相关，它们为多个项目或整个组织共享(如办公楼租金、水电费、行政人员工资)。A描述的是direct costs，B错误(间接成本可通过分摊比率分配)，C错误(间接成本通常由高层而非一线经理控制)。", "knowledgePointIds": [], "knowledgePoint": "间接成本 (Indirect Costs)", "mnemonic": "Direct='你能指着说就花在这个项目上'，Indirect='多个项目分摊，说不清哪个花在哪'。看到'not directly related'→Indirect costs。", "trap": "间接成本是可以分配(allocated)到项目上的(通过分摊比率)，只是不直接归属。B说'不能被分配'是错误的。"}, {"id": "Q92", "num": 92, "type": "single_choice", "point": 1, "stem": "What is the first step in project cost management?", "options": [{"key": "A", "text": "allocate project cost estimates to individual material resources"}, {"key": "B", "text": "plan how costs will be managed"}, {"key": "C", "text": "control project costs and monitor cost performance"}, {"key": "D", "text": "develop several estimates of costs for different types of resources"}], "note": "", "answerKey": "B", "answerText": "plan how costs will be managed", "chapter": "第7章 Project Cost Management", "chapterId": "CH07", "chapterNo": 7, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 7.pdf, Slides 3-4, 7, 44; Textbook Chapter 7 pp.263-298", "sourceExcerpt": "The first step is Plan Cost Management — establishing policies, procedures, and documentation.", "explanationMd": "**答案：** B. plan how costs will be managed\n\n成本管理四大过程按顺序：1)Plan Cost Management(制定成本管理方法指南)→2)Estimate Costs(估算)→3)Determine Budget(确定预算)→4)Control Costs(控制)。第一步永远是Plan。", "knowledgePointIds": [], "knowledgePoint": "规划成本管理 (Plan Cost Management)", "mnemonic": "PMBOK任何知识领域的逻辑都是'先Plan再Do'。成本管理第一步一定是Plan Cost Management。", "trap": "成本管理顺序：Plan Cost Management → Estimate Costs → Determine Budget → Control Costs。"}, {"id": "Q93", "num": 93, "type": "single_choice", "point": 1, "stem": "Which statement is true of an order of magnitude estimate?", "options": [{"key": "A", "text": "It is used to allocate money into an organization's budget."}, {"key": "B", "text": "It provides an estimate of what a project will cost."}, {"key": "C", "text": "Its timeframe is always less than a year prior to project completion."}, {"key": "D", "text": "It is a type of estimate that is done in the final stages of a project."}], "note": "", "answerKey": "B", "answerText": "It provides an estimate of what a project will cost.", "chapter": "第7章 Project Cost Management", "chapterId": "CH07", "chapterNo": 7, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 7.pdf, Slides 17-18, 22; Textbook Chapter 7 pp.263-298", "sourceExcerpt": "An ROM estimate provides a rough idea of what a project will cost, done in early phases.", "explanationMd": "**答案：** B\n\nROM(数量级估算)在项目概念阶段进行，提供项目成本的粗略估算，典型精度-50%到+100%。A是Budgetary Estimate的作用(精度-10%~+25%)，C无此时间限制，D错误：ROM在最早阶段做不是最终阶段。", "knowledgePointIds": [], "knowledgePoint": "数量级估算 (ROM Estimate)", "mnemonic": "ROM是最早期、最粗略的估算(精度-50%到+100%)，用于'要不要继续'的决策判断。", "trap": "ROM在项目最早阶段做(不是最终阶段)，精度很宽(不是精确估算)。用于分配预算的是Budgetary Estimate(-10%~+25%)。"}, {"id": "Q94", "num": 94, "type": "single_choice", "point": 1, "stem": "What term is used for analogous estimates?", "options": [{"key": "A", "text": "bottom-up"}, {"key": "B", "text": "top-down"}, {"key": "C", "text": "parametric"}, {"key": "D", "text": "budgetary"}], "note": "", "answerKey": "B", "answerText": "top-down", "chapter": "第7章 Project Cost Management", "chapterId": "CH07", "chapterNo": 7, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 7.pdf, Slide 22; Textbook Chapter 7 pp.263-298", "sourceExcerpt": "Analogous estimates are also called top-down estimates, based on similar historical projects.", "explanationMd": "**答案：** B. top-down\n\nAnalogous Estimating(类比估算)基于类似历史项目的数据来估算当前项目，被称为top-down是因为从项目整体出发利用历史经验做大尺度估算。A Bottom-up是从工作包逐级汇总(相反方向)，C Parametric使用统计关系和参数，D Budgetary是估算类型名称不是别称。", "knowledgePointIds": [], "knowledgePoint": "类比估算 (Analogous Estimating)", "mnemonic": "Analogous = Top-down ——类比就是用'从上面看'的全局经验来估算。Bottom-up是从每一块砖算起，正好相反。", "trap": "不要把analogous和parametric混淆——analogous靠历史项目类比，parametric靠统计模型和参数。"}, {"id": "Q95", "num": 95, "type": "single_choice", "point": 1, "stem": "Which is most likely to be a reason for inaccuracies in information technology cost estimates?", "options": [{"key": "A", "text": "Estimates take a long time to be worked out."}, {"key": "B", "text": "People lack estimating experience."}, {"key": "C", "text": "Human beings are biased toward overestimation."}, {"key": "D", "text": "Only software development provides the scope for estimates to be accurate."}], "note": "", "answerKey": "B", "answerText": "People lack estimating experience.", "chapter": "第7章 Project Cost Management", "chapterId": "CH07", "chapterNo": 7, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 7.pdf, Slide 23; Textbook Chapter 7 pp.263-298", "sourceExcerpt": "Lack of estimating experience is a primary reason for inaccuracies in IT cost estimates.", "explanationMd": "**答案：** B. People lack estimating experience\n\nIT项目成本估算不准确的最常见原因是估算人员缺乏估算经验。IT项目通常具有高度不确定性、技术新颖性，没有足够历史数据积累。C错误：研究表明人类倾向于低估(optimism bias)而非高估。D本身错误。", "knowledgePointIds": [], "knowledgePoint": "IT成本估算不准确的原因", "mnemonic": "IT项目估不准，最根本原因是估算人员缺乏经验(没有大量历史类似项目数据可参照)。", "trap": "人类倾向于低估(optimism bias)而非高估——C说biased toward overestimation是错的。"}, {"id": "Q96", "num": 96, "type": "single_choice", "point": 1, "stem": "Which statement best defines cost variance?", "options": [{"key": "A", "text": "planned value plus actual costs"}, {"key": "B", "text": "earned value minus the actual cost"}, {"key": "C", "text": "rate of performance minus earned value"}, {"key": "D", "text": "planned value minus the rate of performance"}], "note": "", "answerKey": "B", "answerText": "earned value minus the actual cost", "chapter": "第7章 Project Cost Management", "chapterId": "CH07", "chapterNo": 7, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 7.pdf, Slides 33-36; Textbook Chapter 7 pp.263-298", "sourceExcerpt": "Cost Variance (CV) = Earned Value (EV) - Actual Cost (AC).", "explanationMd": "**答案：** B. earned value minus the actual cost\n\nCost Variance(CV) = EV - AC。正数=低于预算(好)，负数=超预算(差)。A/C/D都非正确公式。SV = EV - PV(进度偏差)。", "knowledgePointIds": [], "knowledgePoint": "成本偏差 (CV = EV - AC)", "mnemonic": "CV和SV都从EV出发：CV = EV - AC(成本减实)，SV = EV - PV(进度减计)。正数=好，负数=差。", "trap": "不要搞混CV和SV：CV = EV - AC(成本偏差)，SV = EV - PV(进度偏差)。公式里的减数不同。"}, {"id": "Q97", "num": 97, "type": "single_choice", "point": 1, "stem": "Which statement best defines schedule variance?", "options": [{"key": "A", "text": "earned value minus the planned value"}, {"key": "B", "text": "earned value minus the actual cost"}, {"key": "C", "text": "planned value plus the earned value"}, {"key": "D", "text": "planned value plus the rate of performance"}], "note": "", "answerKey": "A", "answerText": "earned value minus the planned value", "chapter": "第7章 Project Cost Management", "chapterId": "CH07", "chapterNo": 7, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 7.pdf, Slides 33-36; Textbook Chapter 7 pp.263-298", "sourceExcerpt": "Schedule Variance (SV) = Earned Value (EV) - Planned Value (PV).", "explanationMd": "**答案：** A. earned value minus the planned value\n\nSchedule Variance(SV) = EV - PV。正数=进度提前(好)，负数=进度落后(差)。B是CV(EV-AC)，C/D都非正确公式。", "knowledgePointIds": [], "knowledgePoint": "进度偏差 (SV = EV - PV)", "mnemonic": "SV = EV - PV。正数=进度提前(好)，负数=进度落后(差)。EVM公式口诀：成本减实(CV=EV-AC)，进度减计(SV=EV-PV)。", "trap": "B描述的是CV(EV-AC)不是SV，注意'minus the actual cost'和'minus the planned value'的区别。"}, {"id": "Q98", "num": 98, "type": "single_choice", "point": 1, "stem": "Which process includes defining project scope, benefits, and constraints?", "options": [{"key": "A", "text": "project planning"}, {"key": "B", "text": "business area analysis"}, {"key": "C", "text": "resource allocation"}, {"key": "D", "text": "information technology strategy planning"}], "note": "", "answerKey": "A", "answerText": "project planning", "chapter": "第4章 Project Integration Management", "chapterId": "CH04", "chapterNo": 4, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 4.pdf, Slides 14, 17; Textbook Chapter 4 pp.137-182", "sourceExcerpt": "Project Planning includes defining project scope, benefits, and constraints at the project level.", "explanationMd": "**答案：** A. project planning\n\nIT项目选择四阶段流程：1)IT Strategy Planning(确定IT战略方向-公司级)→2)Business Area Analysis(分析业务领域需求-业务级)→3)Project Planning(定义具体项目的范围、收益和约束-项目级)→4)Resource Allocation(选择项目并分配资源-执行级)。", "knowledgePointIds": [], "knowledgePoint": "IT项目选择四阶段：项目规划", "mnemonic": "'defining scope, benefits, constraints'→ 项目级 → Project Planning。四阶段：IT Strategy → Business Area Analysis → Project Planning → Resource Allocation。", "trap": "Strategy是公司级大方向，Business Area Analysis是业务级需求分析，Resource Allocation是执行级选择分配。"}, {"id": "Q99", "num": 99, "type": "single_choice", "point": 1, "stem": "Which process involves selecting information technology projects and assigning resources?", "options": [{"key": "A", "text": "project planning"}, {"key": "B", "text": "business area analysis"}, {"key": "C", "text": "resource allocation"}, {"key": "D", "text": "information technology strategy planning"}], "note": "", "answerKey": "C", "answerText": "resource allocation", "chapter": "第4章 Project Integration Management", "chapterId": "CH04", "chapterNo": 4, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 4.pdf, Slides 14, 17; Textbook Chapter 4 pp.137-182", "sourceExcerpt": "Resource Allocation involves selecting IT projects and assigning resources to them.", "explanationMd": "**答案：** C. resource allocation\n\nResource Allocation是四阶段流程的最后一步：在确定战略方向、分析业务需求、定义具体项目之后，选择哪些IT项目值得投资并为其分配资源。A Project Planning定义项目范围和约束，B Business Area Analysis分析业务需求，D IT Strategy Planning确定IT战略方向。", "knowledgePointIds": [], "knowledgePoint": "IT项目选择四阶段：资源分配", "mnemonic": "'selecting projects, assigning resources'→ 执行级 → Resource Allocation。这是四阶段中的最后一步：选项目、分资源。", "trap": "不要跟Project Planning混淆——Planning是定义范围和约束，Resource Allocation才是选择和分配。"}, {"id": "Q100", "num": 100, "type": "single_choice", "point": 1, "stem": "What term is used for benefits minus costs?", "options": [{"key": "A", "text": "cost of capital"}, {"key": "B", "text": "cash flow"}, {"key": "C", "text": "discount factor"}, {"key": "D", "text": "opportunity cost of capital"}], "note": "", "answerKey": "B", "answerText": "cash flow", "chapter": "第7章 Project Cost Management", "chapterId": "CH07", "chapterNo": 7, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 7.pdf, Slides 5, 10; Textbook Chapter 7 pp.263-298", "sourceExcerpt": "Cash flow = benefits - costs. It is the simplest measure of net financial flow.", "explanationMd": "**答案：** B. cash flow\n\nCash Flow(现金流)=Benefits-Costs(收益减成本)。A Cost of capital是融资成本(用作NPV的贴现率)，C Discount factor是折现因子，D Opportunity cost of capital是资本机会成本。", "knowledgePointIds": [], "knowledgePoint": "现金流 (Cash Flow)", "mnemonic": "Cash Flow = Benefits - Costs。这是最基本的现金流定义。正现金流=有赚头，负现金流=亏了。", "trap": "不要跟NPV(折现后的总价值)或ROI((收益-成本)/成本)混淆。Cash flow只是做减法。"}, {"id": "Q101", "num": 101, "type": "single_choice", "point": 1, "stem": "What is the first step in determining the NPV?", "options": [{"key": "A", "text": "determine the estimated costs and benefits for the life of the project and the products it produces"}, {"key": "B", "text": "determine the discount rate"}, {"key": "C", "text": "calculate the net present value"}, {"key": "D", "text": "determine the cash flow"}], "note": "", "answerKey": "A", "answerText": "determine the estimated costs and benefits for the life of the project and the products it produces", "chapter": "第4章 Project Integration Management", "chapterId": "CH04", "chapterNo": 4, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 4.pdf, Slides 17-18, 21-22; Textbook Chapter 4 pp.137-182", "sourceExcerpt": "Step 1 of NPV: determine estimated costs and benefits for the project's life cycle.", "explanationMd": "**答案：** A\n\n计算NPV三步顺序：1)确定项目生命周期各期的估算成本和收益(先有现金流数据)→2)确定贴现率(discount rate)→3)计算NPV(将各期现金流按贴现率折现后求和)。A描述的是第一步。D是A的结果(先有成本和收益才能算出现金流)。", "knowledgePointIds": [], "knowledgePoint": "净现值 (NPV) 计算步骤", "mnemonic": "NPV三步：1)确定各期成本和收益(即确定现金流)→2)确定贴现率→3)计算NPV。第一步永远是收集数据。", "trap": "第一步是'determine costs and benefits'而非'determine the discount rate'——没有数据贴现率无从用起。"}, {"id": "Q102", "num": 102, "type": "single_choice", "point": 1, "stem": "What statement is true regarding a return on investment or ROI?", "options": [{"key": "A", "text": "It is always a percentage."}, {"key": "B", "text": "It is always a positive number."}, {"key": "C", "text": "It is the result of adding the project costs to the profits."}, {"key": "D", "text": "The lower it is, the better."}], "note": "", "answerKey": "A", "answerText": "It is always a percentage.", "chapter": "第4章 Project Integration Management", "chapterId": "CH04", "chapterNo": 4, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 4.pdf, Slides 22, 25, 39; Textbook Chapter 4 pp.137-182", "sourceExcerpt": "ROI = (Benefits - Costs) / Costs × 100%, always expressed as a percentage.", "explanationMd": "**答案：** A. It is always a percentage.\n\nROI始终以百分比形式表达：ROI=(Gain-Cost)/Cost×100%。B错误：ROI可以为负数(亏损时)。C错误：ROI是收益率=(利润/成本)，不是'成本+利润'。D错误：ROI越高越好。", "knowledgePointIds": [], "knowledgePoint": "投资回报率 (ROI)", "mnemonic": "ROI=(收益-成本)/成本×100%，始终是百分比。越高越好，可以为负数(亏损时)。", "trap": "ROI可以为负数(项目亏损时)，B说always positive是错的。D说越低越好完全反了——ROI越高越好。"}, {"id": "Q103", "num": 103, "type": "single_choice", "point": 1, "stem": "What document used to coordinate all project planning documents and help guide a project's execution and control?", "options": [{"key": "A", "text": "project management plan"}, {"key": "B", "text": "statement of work"}, {"key": "C", "text": "scope statement"}, {"key": "D", "text": "business case"}], "note": "", "answerKey": "A", "answerText": "project management plan", "chapter": "第4章 Project Integration Management", "chapterId": "CH04", "chapterNo": 4, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 4.pdf, Slides 3, 32, 36, 55; Textbook Chapter 4 pp.137-182", "sourceExcerpt": "The Project Management Plan coordinates all planning documents and guides execution and control.", "explanationMd": "**答案：** A. project management plan\n\nProject Management Plan整合所有辅助计划和基线，用于协调各计划并指导项目执行和控制。B Statement of Work描述采购的产品/服务，C Scope Statement仅定义范围，D Business Case论证项目商业价值。", "knowledgePointIds": [], "knowledgePoint": "项目管理计划 (Project Management Plan)", "mnemonic": "PM Plan = 协调所有子计划 + 指导执行和控制。就像乐团总谱——协调各乐器组的演奏。", "trap": "不要把Statement of Work(采购描述)或Business Case(商业论证)跟PM Plan(协调所有计划)混淆。"}, {"id": "Q104", "num": 104, "type": "single_choice", "point": 1, "stem": "Which section of the project plan lists the planned dates for completing key deliverables?", "options": [{"key": "A", "text": "schedule"}, {"key": "B", "text": "closing"}, {"key": "C", "text": "budget"}, {"key": "D", "text": "objectives"}], "note": "", "answerKey": "A", "answerText": "schedule", "chapter": "第4章 Project Integration Management", "chapterId": "CH04", "chapterNo": 4, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 4.pdf, Slides 33, 35, 43; Textbook Chapter 4 pp.137-182", "sourceExcerpt": "The Schedule section lists planned dates for completing key deliverables.", "explanationMd": "**答案：** A. schedule\n\n项目管理计划中的Schedule章节列出关键可交付成果的计划完成日期，通常以甘特图、里程碑列表或网络图形式呈现。B Closing描述如何收尾，C Budget描述成本估算和资金，D Objectives描述项目目标。", "knowledgePointIds": [], "knowledgePoint": "项目计划的Schedule章节", "mnemonic": "Schedule章节=关键可交付成果的计划完成日期。问'什么时候交付什么东西'→翻进度表(schedule)。", "trap": "Closing描述如何收尾，Budget描述成本和资金，Objectives描述项目目标——都不涉及具体日期。"}, {"id": "Q105", "num": 105, "type": "single_choice", "point": 1, "stem": "Which section of the project management plan includes external interfaces, internal structure, as well as roles and responsibilities?", "options": [{"key": "A", "text": "overview"}, {"key": "B", "text": "technical processes"}, {"key": "C", "text": "project organization"}, {"key": "D", "text": "supporting processes"}], "note": "", "answerKey": "C", "answerText": "project organization", "chapter": "第4章 Project Integration Management", "chapterId": "CH04", "chapterNo": 4, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 5.pdf, Slide 39; Textbook Chapter 4 pp.137-182", "sourceExcerpt": "The Project Organization section describes external interfaces, internal structure, roles and responsibilities.", "explanationMd": "**答案：** C. project organization\n\nProject Organization章节描述项目的组织结构：外部接口(与其他组织/系统的交互)、内部结构(团队分层和汇报关系)、角色和职责(谁负责什么)。是项目的'组织架构图+岗位说明书'合集。", "knowledgePointIds": [], "knowledgePoint": "项目计划的Project Organization章节", "mnemonic": "Project Organization = 组织架构图+岗位说明书：外部接口(跟谁对接)、内部结构(层级怎么排)、角色职责(每个人负责什么)。", "trap": "不要跟Technical processes(技术流程)或Overview(概述)混淆。Organization专门管'谁向谁汇报、谁跟外面对接'。"}, {"id": "Q106", "num": 106, "type": "single_choice", "point": 1, "stem": "Which process includes defining project scope, benefits, and constraints?", "options": [{"key": "A", "text": "project planning"}, {"key": "B", "text": "business area analysis"}, {"key": "C", "text": "resource allocation"}, {"key": "D", "text": "information technology strategy planning"}], "note": "", "answerKey": "A", "answerText": "project planning", "chapter": "第4章 Project Integration Management", "chapterId": "CH04", "chapterNo": 4, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 4.pdf, Slides 14, 17; Textbook Chapter 4 pp.137-182", "sourceExcerpt": "Project Planning includes defining project scope, benefits, and constraints.", "explanationMd": "**答案：** A. project planning\n\n本题与Q38(Q98)内容相同。Project Planning是IT项目选择四阶段中的项目级规划，包括定义项目范围、收益和约束条件。", "knowledgePointIds": [], "knowledgePoint": "IT项目选择四阶段：项目规划", "mnemonic": "与Q38(Q98)相同。'defining scope, benefits, constraints'→ Project Planning。", "trap": "虽与Q38题干完全相同，但这是测试题库中确实存在的重复题，答案一致。"}, {"id": "Q107", "num": 107, "type": "single_choice", "point": 1, "stem": "Which type of person achieves a balance between risk and payoff?", "options": [{"key": "A", "text": "risk-seeking"}, {"key": "B", "text": "risk-averse"}, {"key": "C", "text": "risk-fearing"}, {"key": "D", "text": "risk-neutral"}], "note": "", "answerKey": "D", "answerText": "risk-neutral", "chapter": "第11章 Project Risk Management", "chapterId": "CH11", "chapterNo": 11, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 11.pdf, Slide 13; Textbook Chapter 11 pp.425-464", "sourceExcerpt": "A risk-neutral person achieves a balance between risk and payoff, deciding based on expected value.", "explanationMd": "**答案：** D. risk-neutral\n\nRisk-neutral(风险中性)的人在风险和收益之间寻求平衡，基于期望值(EMV)做决策。A Risk-seeking偏好高风险高收益，B Risk-averse回避风险(宁可损失潜在收益)，C Risk-fearing不是标准项目管理术语。", "knowledgePointIds": [], "knowledgePoint": "风险态度：风险中性 (Risk-Neutral)", "mnemonic": "Risk-neutral在风险和收益之间寻求平衡，基于期望值决策。Risk-averse回避风险，Risk-seeking偏好高风险高收益。", "trap": "Risk-neutral是'平衡'不是'无所谓'。Risk-fearing不是标准PM术语(通常归入risk-averse的极端形式)。"}, {"id": "Q108", "num": 108, "type": "single_choice", "point": 1, "stem": "Which is a fact-finding technique that can be used for collecting information in face-to-face, phone, e-mail, or instant-messaging discussions?", "options": [{"key": "A", "text": "brainstorming"}, {"key": "B", "text": "Monte Carlo analysis"}, {"key": "C", "text": "the Delphi technique"}, {"key": "D", "text": "interviewing"}], "note": "", "answerKey": "D", "answerText": "interviewing", "chapter": "第11章 Project Risk Management", "chapterId": "CH11", "chapterNo": 11, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 11.pdf, Slides 28-29, 31; Textbook Chapter 11 pp.425-464", "sourceExcerpt": "Interviewing is a fact-finding technique using face-to-face, phone, e-mail, or instant-messaging discussions.", "explanationMd": "**答案：** D. interviewing\n\nInterviewing(访谈)是一种通过面对面、电话、电子邮件或即时消息等方式从专家或干系人处收集信息的事实收集技术。A Brainstorming是团队头脑风暴，B Monte Carlo是统计模拟技术，C Delphi是匿名多轮专家调研。", "knowledgePointIds": [], "knowledgePoint": "访谈 (Interviewing)", "mnemonic": "Interviewing可通过多种渠道进行：面对面、电话、邮件、即时消息。核心是'问问题+记录回答'。", "trap": "Brainstorming是群体创意技术(非一对一)，Delphi是匿名多轮问卷(非即时通讯)，Monte Carlo是定量分析模拟。"}, {"id": "Q109", "num": 109, "type": "single_choice", "point": 1, "stem": "Which process involves prioritizing risks based on their probability of occurrence and impact?", "options": [{"key": "A", "text": "performing qualitative risk analysis"}, {"key": "B", "text": "planning risk management"}, {"key": "C", "text": "monitoring and controlling risks"}, {"key": "D", "text": "project closing"}], "note": "", "answerKey": "A", "answerText": "performing qualitative risk analysis", "chapter": "第11章 Project Risk Management", "chapterId": "CH11", "chapterNo": 11, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 11.pdf, Slides 3, 15, 45, 61; Textbook Chapter 11 pp.425-464", "sourceExcerpt": "Qualitative Risk Analysis prioritizes risks based on probability of occurrence and impact.", "explanationMd": "**答案：** A. performing qualitative risk analysis\n\nPerform Qualitative Risk Analysis基于已识别风险的发生概率和影响程度进行优先级排序(使用概率-影响矩阵)。B Plan Risk Management制定方法，C Monitor and Control跟踪执行，D Project Closing是收尾。", "knowledgePointIds": [], "knowledgePoint": "定性风险分析 (Qualitative Risk Analysis)", "mnemonic": "看到'prioritizing'+'probability and impact'→ Qualitative Risk Analysis。定性=排序，定量=数值化。", "trap": "Qualitative是排序(prioritize)，Quantitative是数值化分析(quantify)。不要搞混两者的核心任务。"}, {"id": "Q110", "num": 110, "type": "single_choice", "point": 1, "stem": "Which action involves doing whatever you can to make sure the positive risk happens?", "options": [{"key": "A", "text": "risk exploitation"}, {"key": "B", "text": "risk sharing"}, {"key": "C", "text": "risk enhancement"}, {"key": "D", "text": "risk acceptance"}], "note": "", "answerKey": "A", "answerText": "risk exploitation", "chapter": "第11章 Project Risk Management", "chapterId": "CH11", "chapterNo": 11, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 11.pdf, Slides 4, 11, 56; Textbook Chapter 11 pp.425-464", "sourceExcerpt": "Exploitation means doing whatever you can to make sure the positive risk (opportunity) happens.", "explanationMd": "**答案：** A. risk exploitation\n\nRisk Exploitation(风险开拓)是针对积极风险(机会)的最激进策略——尽一切努力确保机会一定发生。B Sharing将风险所有权部分转移给第三方，C Enhancement增加概率/影响(没Exploit那么绝对)，D Acceptance不主动追求。", "knowledgePointIds": [], "knowledgePoint": "风险开拓 (Risk Exploitation)", "mnemonic": "积极风险四大策略：Exploit(尽一切努力确保发生)>Enhance(提高概率)>Share(与第三方合作)>Accept(不主动)。", "trap": "Exploit追求100%让它发生，Enhance只是增加发生概率。Exploit更激进。不要选Enhance。"}, {"id": "Q111", "num": 111, "type": "single_choice", "point": 1, "stem": "_____ are unplanned responses to risk events used when project teams do not have contingency plans in place.", "options": [{"key": "A", "text": "Workarounds"}, {"key": "B", "text": "Fallback plans"}, {"key": "C", "text": "Contingency plans"}, {"key": "D", "text": "Triggers"}], "note": "", "answerKey": "A", "answerText": "Workarounds", "chapter": "第11章 Project Risk Management", "chapterId": "CH11", "chapterNo": 11, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 11.pdf, Slide 58; Textbook Chapter 11 pp.425-464", "sourceExcerpt": "Workarounds are unplanned responses to risk events when no contingency plans are in place.", "explanationMd": "**答案：** A. Workarounds\n\nWorkarounds(权变措施)是对已发生的、没有预先制定应急计划的负面风险事件采取的非计划性临时应对措施。B Fallback plans是应急计划失效时的备用方案(仍有计划)，C Contingency plans是预先制定好的，D Triggers是指示风险即将发生的触发条件。", "knowledgePointIds": [], "knowledgePoint": "权变措施 (Workarounds)", "mnemonic": "有准备=Contingency/Fallback，没准备临时凑=Workaround。题干中'unplanned'和'do not have contingency plans'是workaround的关键词。", "trap": "Fallback plans和Contingency plans都是有预先计划的，与题干'unplanned'矛盾。Triggers是触发条件不是应对措施。"}, {"id": "Q112", "num": 112, "type": "single_choice", "point": 1, "stem": "What are the system's special characteristics that appeal to users?", "options": [{"key": "A", "text": "features"}, {"key": "B", "text": "outputs"}, {"key": "C", "text": "yields"}, {"key": "D", "text": "metrics"}], "note": "", "answerKey": "A", "answerText": "features", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 8.pdf, Slide 11; Textbook Chapter 8 pp.299-342", "sourceExcerpt": "Features are the system's special characteristics that appeal to users.", "explanationMd": "**答案：** A. features\n\nFeatures(特性)是系统或产品的特殊属性，正是这些特性吸引用户(如手机的摄像头像素、App的夜间模式)。B Outputs是系统输出结果，C Yields是产出率，D Metrics是度量指标。", "knowledgePointIds": [], "knowledgePoint": "特性 (Features)", "mnemonic": "Features=系统吸引用户的特殊属性/卖点。Functionality=基础功能(能做什么)，Features=差异化吸引力(为什么选它)。", "trap": "不要把Outputs(系统的输出结果)或Metrics(度量指标)当成吸引用户的特性。Features是'打动用户的卖点'。"}, {"id": "Q113", "num": 113, "type": "single_choice", "point": 1, "stem": "Which addresses how well a product or service performs the customer's intended use?", "options": [{"key": "A", "text": "reliability"}, {"key": "B", "text": "performance"}, {"key": "C", "text": "maintainability"}, {"key": "D", "text": "functionality"}], "note": "", "answerKey": "B", "answerText": "performance", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 8.pdf, Slide 11; Textbook Chapter 8 pp.299-342", "sourceExcerpt": "Performance addresses how well a product or service performs the customer's intended use.", "explanationMd": "**答案：** B. performance\n\nPerformance(性能)衡量产品或服务执行客户预期用途的'好坏程度'——'用起来好不好'。A Reliability(可靠性)是正常运行的概率，C Maintainability(可维护性)是维护的便利程度，D Functionality(功能性)是产品能做什么。", "knowledgePointIds": [], "knowledgePoint": "性能 (Performance)", "mnemonic": "Performance='好不好用'(how well does it work)，Functionality='能不能用'(what can it do)，Reliability='多久不会坏'，Maintainability='好不好修'。", "trap": "Functionality问的是'能做哪些事'，Performance问的是'做这些事做得怎么样'。不要混。"}, {"id": "Q114", "num": 114, "type": "single_choice", "point": 1, "stem": "Which addresses the ease of performing maintenance on a product?", "options": [{"key": "A", "text": "reliability"}, {"key": "B", "text": "performance"}, {"key": "C", "text": "maintainability"}, {"key": "D", "text": "functionality"}], "note": "", "answerKey": "C", "answerText": "maintainability", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 8.pdf, Slide 11; Textbook Chapter 8 pp.299-342", "sourceExcerpt": "Maintainability addresses the ease of performing maintenance on a product.", "explanationMd": "**答案：** C. maintainability\n\nMaintainability(可维护性)指产品维护的便利程度——'修起来容不容易'。高可维护性意味着修改和升级难度低、排错效率高、维护成本低。A Reliability是可靠度(多久不会坏)，B Performance是性能(好不好用)，D Functionality是功能性(能做什么)。", "knowledgePointIds": [], "knowledgePoint": "可维护性 (Maintainability)", "mnemonic": "Maintainability='好不好修'(ease of maintenance)。高可维护性=修改升级难度低、排错效率高、维护成本低。", "trap": "不要把Maintainability(好不好修)和Reliability(会不会坏)搞混。一个管'修起来麻烦不'，一个管'多久不坏'。"}, {"id": "Q115", "num": 115, "type": "single_choice", "point": 1, "stem": "What process is used to generate ideas for quality improvements by comparing specific project practices or product characteristics to those of other projects or products within or outside the performing organization?", "options": [{"key": "A", "text": "prototyping"}, {"key": "B", "text": "systems thinking"}, {"key": "C", "text": "mind mapping"}, {"key": "D", "text": "benchmarking"}], "note": "", "answerKey": "D", "answerText": "benchmarking", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 8.pdf, Slide 13; Textbook Chapter 8 pp.299-342", "sourceExcerpt": "Benchmarking generates ideas for quality improvements by comparing to other projects or products.", "explanationMd": "**答案：** D. benchmarking\n\nBenchmarking(标杆对照)通过将本项目的实践或产品特性与其他项目(内部或外部)进行比较，产生质量改进思路。A Prototyping是制作可工作的系统模型，B Systems thinking是系统性思维方式，C Mind mapping是发散和整理思路的工具。", "knowledgePointIds": [], "knowledgePoint": "标杆对照 (Benchmarking)", "mnemonic": "Benchmarking='看看别人家怎么做的'→与最佳实践比较以发现改进点。核心动作是'比一比，找出你能学到什么'。", "trap": "不要把Benchmarking和Prototyping(做样品验证需求)或Mind mapping(发散整理思路)混淆。"}, {"id": "Q116", "num": 116, "type": "single_choice", "point": 1, "stem": "Which graphic display of data illustrates the results of a process over time?", "options": [{"key": "A", "text": "statistical sampling chart"}, {"key": "B", "text": "Pareto chart"}, {"key": "C", "text": "Six Sigma chart"}, {"key": "D", "text": "control chart"}], "note": "", "answerKey": "D", "answerText": "control chart", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 8.pdf, Slides 18-19, 67; Textbook Chapter 8 pp.299-342", "sourceExcerpt": "A control chart illustrates the results of a process over time, with UCL, mean, and LCL.", "explanationMd": "**答案：** D. control chart\n\nControl Chart(控制图)按时间顺序展示过程数据，包含中心线(目标值)、上控制限(UCL)和下控制限(LCL)，用于判断过程是否稳定。B Pareto chart按频率排序(不按时间)，C Six Sigma chart不是标准图表名称。", "knowledgePointIds": [], "knowledgePoint": "控制图 (Control Chart)", "mnemonic": "Control Chart=按时间展示过程结果(有中心线+上下控制限)。Pareto Chart=排序看谁问题最多(不按时间)。", "trap": "Pareto chart是柱状图按频率排序(不按时间)，Control chart才是'overtime'的图表。注意题干中的'overtime'关键词。"}, {"id": "Q117", "num": 117, "type": "single_choice", "point": 1, "stem": "Which chart helps users identify the vital few contributors that account for most quality problems in a system?", "options": [{"key": "A", "text": "Gantt"}, {"key": "B", "text": "Pareto"}, {"key": "C", "text": "control"}, {"key": "D", "text": "tracking Gantt"}], "note": "", "answerKey": "B", "answerText": "Pareto", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 8.pdf, Slides 27, 67; Textbook Chapter 8 pp.299-342", "sourceExcerpt": "A Pareto chart helps identify the vital few contributors that account for most quality problems.", "explanationMd": "**答案：** B. Pareto\n\nPareto Chart(帕累托图)基于帕累托原理(80/20法则)，帮助识别导致绝大多数质量问题的'关键少数'(vital few)原因。按频率降序排列的柱状图+累积百分比折线。A Gantt是进度管理，C Control是监控过程稳定性，D Tracking Gantt比较计划和实际进度。", "knowledgePointIds": [], "knowledgePoint": "帕累托图 (Pareto Chart)", "mnemonic": "Pareto基于80/20法则——80%的问题源于20%的原因。'vital few'直接指向Pareto概念。", "trap": "Gantt和Tracking Gantt是进度管理工具，Control chart是监控过程稳定性的——都不管'哪些问题最重要'。"}, {"id": "Q118", "num": 118, "type": "single_choice", "point": 1, "stem": "Which process involves choosing part of a population of interest for inspection?", "options": [{"key": "A", "text": "statistical sampling"}, {"key": "B", "text": "conformance"}, {"key": "C", "text": "system testing"}, {"key": "D", "text": "fitness for use"}], "note": "", "answerKey": "A", "answerText": "statistical sampling", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 8.pdf, Slides 4, 33; Textbook Chapter 8 pp.299-342", "sourceExcerpt": "Statistical sampling involves choosing part of a population of interest for inspection.", "explanationMd": "**答案：** A. statistical sampling\n\nStatistical Sampling(统计抽样)是从整体(population)中选取部分样本进行检验，以此推断整体质量状况的过程。B Conformance是符合度(检验的结果)，C System Testing是整个系统的测试，D Fitness for use是适用性(质量概念维度)。", "knowledgePointIds": [], "knowledgePoint": "统计抽样 (Statistical Sampling)", "mnemonic": "Statistical Sampling='抽查'——从整体中选取部分样本检验来推断整体质量。当100%检验不经济或不可行时使用。", "trap": "Conformance是检验结果(符合/不符合)，不是抽样方法。System Testing测试整个系统不强调抽样。"}, {"id": "Q119", "num": 119, "type": "single_choice", "point": 1, "stem": "Which five-phase improvement process do projects that use Six Sigma principles for quality control normally follow?", "options": [{"key": "A", "text": "DMAIC"}, {"key": "B", "text": "weighted scoring model"}, {"key": "C", "text": "configuration management"}, {"key": "D", "text": "use case modelling"}], "note": "", "answerKey": "A", "answerText": "DMAIC", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 8.pdf, Slides 4, 35-38; Textbook Chapter 8 pp.299-342", "sourceExcerpt": "DMAIC (Define, Measure, Analyze, Improve, Control) is the Six Sigma five-phase improvement process.", "explanationMd": "**答案：** A. DMAIC\n\nDMAIC是Six Sigma质量改进的标准五阶段流程：Define(定义问题)、Measure(测量现状)、Analyze(分析根因)、Improve(改善流程)、Control(控制保持)。目标是将过程缺陷率降低到每百万次3.4次。", "knowledgePointIds": [], "knowledgePoint": "六西格玛 DMAIC", "mnemonic": "DMAIC = Define定义, Measure测量, Analyze分析, Improve改进, Control控制。Six Sigma的五阶段改进流程。", "trap": "Weighted scoring model是项目选择方法，Configuration management是整合管理，Use case modelling是需求分析。"}, {"id": "Q120", "num": 120, "type": "single_choice", "point": 1, "stem": "Which test is done to test each individual component (often a program) to ensure that it is as defect-free as possible?", "options": [{"key": "A", "text": "integration"}, {"key": "B", "text": "unit"}, {"key": "C", "text": "user acceptance"}, {"key": "D", "text": "system"}], "note": "", "answerKey": "B", "answerText": "unit", "chapter": "第8章 Project Quality Management", "chapterId": "CH08", "chapterNo": 8, "category": "1", "sharedGroup": "无", "source": "PPT/Chapter 8.pdf, Slide 49; Textbook Chapter 8 pp.299-342", "sourceExcerpt": "Unit testing tests each individual component to ensure it is as defect-free as possible.", "explanationMd": "**答案：** B. unit\n\nUnit Testing(单元测试)对软件的最小可测试单元(单个函数/方法/模块)进行独立测试，确保尽可能无缺陷。测试顺序：Unit(最先，开发者)→Integration(组件交互)→System(整个系统)→User Acceptance(用户验收，最后)。", "knowledgePointIds": [], "knowledgePoint": "单元测试 (Unit Testing)", "mnemonic": "Unit Testing=测试每个独立组件(最底层)。测试顺序：Unit→Integration→System→User Acceptance。", "trap": "Integration test测试组件间交互(不是单个组件)，System test测试整个集成系统，UAT从用户角度验证。"}];
})(typeof window !== 'undefined' ? window : globalThis);
